export const flashcardDecks: FlashcardDeck[] = [
  {
    id: 'literary-techniques',
    title: 'Literary & Language Techniques',
    description: '50 essential techniques for GCSE English',
    category: 'Techniques',
    board: 'All',
    cards: [
      { id: 'lt-1', front: 'Metaphor', back: 'A comparison that says something IS something else, without using "like" or "as."\n\nExample: "All the world\'s a stage" (Shakespeare)\n\nEffect: Creates a vivid image and implies a deeper connection between two things.' },
      { id: 'lt-2', front: 'Simile', back: 'A comparison using "like" or "as."\n\nExample: "Her smile was like sunshine after rain."\n\nEffect: Makes descriptions more vivid by linking the unfamiliar to the familiar.' },
      { id: 'lt-3', front: 'Personification', back: 'Giving human qualities to something non-human.\n\nExample: "The wind howled in anger."\n\nEffect: Makes abstract ideas or natural forces feel alive and relatable.' },
      { id: 'lt-4', front: 'Alliteration', back: 'Repetition of the same consonant sound at the start of nearby words.\n\nExample: "Peter Piper picked a peck of pickled peppers."\n\nEffect: Creates rhythm, emphasis, or a particular mood (e.g., harsh alliteration with "c" or "k").' },
      { id: 'lt-5', front: 'Sibilance', back: 'Repetition of "s," "sh," or soft "c" sounds.\n\nExample: "The snake slithered silently through the grass."\n\nEffect: Often creates a sinister, secretive, or soothing atmosphere.' },
      { id: 'lt-6', front: 'Onomatopoeia', back: 'A word that sounds like what it describes.\n\nExample: "The bees buzzed around the flowers."\n\nEffect: Makes the reader hear the sound, creating an immersive sensory experience.' },
      { id: 'lt-7', front: 'Pathetic Fallacy', back: 'Using weather or the environment to reflect a character\'s mood.\n\nExample: "Rain lashed the windows as she sobbed."\n\nEffect: Reinforces emotion and atmosphere without stating feelings directly.' },
      { id: 'lt-8', front: 'Oxymoron', back: 'Two contradictory words placed together.\n\nExample: "A deafening silence filled the room."\n\nEffect: Highlights conflict, tension, or complexity within a character or situation.' },
      { id: 'lt-9', front: 'Juxtaposition', back: 'Placing two contrasting ideas, characters, or images side by side.\n\nExample: "It was the best of times, it was the worst of times." (Dickens)\n\nEffect: Highlights differences and forces the reader to compare.' },
      { id: 'lt-10', front: 'Hyperbole', back: 'Deliberate exaggeration for emphasis or effect.\n\nExample: "I\'ve told you a million times."\n\nEffect: Conveys strong emotion or makes a point dramatically.' },
      { id: 'lt-11', front: 'Irony', back: 'When words mean the opposite of what they say, or events turn out differently from expectations.\n\nExample: A fire station burns down.\n\nTypes: Verbal irony, dramatic irony, situational irony.' },
      { id: 'lt-12', front: 'Symbolism', back: 'Using an object, colour, or image to represent a deeper meaning.\n\nExample: A red rose symbolising love.\n\nEffect: Adds layers of meaning beyond the literal.' },
      { id: 'lt-13', front: 'Foreshadowing', back: 'Hints or clues about what will happen later in the text.\n\nExample: "Little did he know, this would be his last journey."\n\nEffect: Builds tension, suspense, or dramatic irony.' },
      { id: 'lt-14', front: 'Rhetorical Question', back: 'A question asked for effect, not expecting an answer.\n\nExample: "How long must we tolerate this injustice?"\n\nEffect: Engages the reader and makes them think. Implies the answer is obvious.' },
      { id: 'lt-15', front: 'Tricolon (Rule of Three)', back: 'A list of three words, phrases, or clauses for emphasis.\n\nExample: "Government of the people, by the people, for the people."\n\nEffect: Creates rhythm, makes ideas memorable, builds to a climax.' },
      { id: 'lt-16', front: 'Anaphora', back: 'Repeating a word or phrase at the start of consecutive sentences or clauses.\n\nExample: "We shall fight on the beaches, we shall fight on the landing grounds, we shall fight in the fields."\n\nEffect: Creates rhythm and emphasis. Builds emotional power.' },
      { id: 'lt-17', front: 'Emotive Language', back: 'Words deliberately chosen to provoke an emotional response.\n\nExample: "The helpless, innocent children were abandoned."\n\nEffect: Makes the reader feel sympathy, anger, fear, etc.' },
      { id: 'lt-18', front: 'Imperative', back: 'A command or instruction.\n\nExample: "Join us. Fight back. Make your voice heard."\n\nEffect: Creates urgency and directly engages the reader.' },
      { id: 'lt-19', front: 'Direct Address', back: 'Speaking directly to the reader using "you."\n\nExample: "You know this is wrong."\n\nEffect: Creates a personal connection and makes the argument feel inescapable.' },
      { id: 'lt-20', front: 'Semantic Field', back: 'A group of words that all relate to the same topic.\n\nExample: "The battlefield was littered with shells, trenches stretched for miles, and the soldiers marched on." (semantic field of war)\n\nEffect: Creates a sustained mood or reinforces a theme.' },
      { id: 'lt-21', front: 'Tone', back: 'The writer\'s attitude or feeling conveyed through their language choices.\n\nExamples: bitter, nostalgic, sarcastic, hopeful, menacing.\n\nHow to identify: Look at word connotations, sentence length, and punctuation.' },
      { id: 'lt-22', front: 'Imagery', back: 'Language that appeals to the senses (sight, sound, touch, taste, smell).\n\nExample: "The golden wheat swayed in the warm breeze, filling the air with a sweet, earthy scent."\n\nEffect: Makes the reader feel as if they are there.' },
      { id: 'lt-23', front: 'Extended Metaphor', back: 'A metaphor that continues across several lines or an entire text.\n\nExample: Shakespeare\'s "All the world\'s a stage, and all the men and women merely players" continues with "exits and entrances."\n\nEffect: Develops a complex comparison in depth.' },
      { id: 'lt-24', front: 'Plosive Sounds', back: 'Hard consonant sounds: b, d, g, p, t, k.\n\nExample: "The bitter, brutal cold bit through his coat."\n\nEffect: Creates a harsh, aggressive, or violent tone.' },
      { id: 'lt-25', front: 'Caesura', back: 'A pause in the middle of a line of poetry, usually marked by punctuation.\n\nExample: "I wandered lonely. As a cloud."\n\nEffect: Creates emphasis, disrupts rhythm, reflects meaning.' },
      { id: 'lt-26', front: 'Enjambment', back: 'When a sentence runs over from one line of poetry to the next without punctuation.\n\nEffect: Creates a sense of momentum, urgency, or overflow of emotion.' },
      { id: 'lt-27', front: 'Volta', back: 'A turning point in a poem where the mood, argument, or focus shifts.\n\nOften found: At the start of the final couplet in a sonnet (line 9 or 13).\n\nEffect: Creates contrast and surprise.' },
      { id: 'lt-28', front: 'Stanza', back: 'A group of lines in a poem (like a paragraph in prose).\n\nStanza lengths carry meaning: short stanzas can feel clipped or urgent; long stanzas can feel expansive.' },
      { id: 'lt-29', front: 'Free Verse', back: 'Poetry without a regular rhyme scheme or metre.\n\nEffect: Can feel conversational, natural, or rebellious against tradition.' },
      { id: 'lt-30', front: 'Sonnet', back: 'A 14-line poem, usually about love.\n\nShakespearean: 3 quatrains + couplet (ABAB CDCD EFEF GG)\nPetrarchan: Octave + sestet (ABBAABBA + CDECDE)\n\nVolta usually at line 9 or 13.' },
      { id: 'lt-31', front: 'Dramatic Monologue', back: 'A poem where a single character speaks to a silent listener, revealing their personality.\n\nExample: Robert Browning\'s "My Last Duchess"\n\nEffect: Shows character through voice rather than description.' },
      { id: 'lt-32', front: 'First Person Narrator', back: 'The story is told using "I" by a character within the story.\n\nEffect: Creates intimacy and subjectivity. The reader only sees what this character sees.' },
      { id: 'lt-33', front: 'Third Person Omniscient', back: 'The narrator knows everything — all characters\' thoughts and feelings.\n\nEffect: Gives the reader a god-like perspective. Can create dramatic irony.' },
      { id: 'lt-34', front: 'Unreliable Narrator', back: 'A narrator whose account cannot be fully trusted.\n\nClues: Contradictions, bias, gaps in memory, defensive tone.\n\nEffect: Creates suspense and forces the reader to question what is real.' },
      { id: 'lt-35', front: 'Motif', back: 'A recurring image, symbol, or idea throughout a text.\n\nExample: The green light in The Great Gatsby.\n\nEffect: Reinforces themes and creates structural cohesion.' },
      { id: 'lt-36', front: 'Allegory', back: 'A story where characters and events represent abstract ideas or moral concepts.\n\nExample: Animal Farm is an allegory for the Russian Revolution.\n\nEffect: Communicates political or moral messages through narrative.' },
      { id: 'lt-37', front: 'Gothic Genre', back: 'A literary genre characterised by darkness, decay, supernatural elements, and psychological terror.\n\nConventions: Isolated settings, doubles/duality, madness, secrets.\n\nExample: Jekyll and Hyde, Frankenstein, Dracula.' },
      { id: 'lt-38', front: 'Bildungsroman', back: 'A coming-of-age story that follows a character\'s moral and psychological development.\n\nExample: Great Expectations, Jane Eyre.\n\nKey feature: The protagonist learns and grows through their experiences.' },
      { id: 'lt-39', front: 'Asyndetic List', back: 'A list without conjunctions (and, or, but).\n\nExample: "He ran, stumbled, fell, lay still."\n\nEffect: Creates pace, urgency, or an overwhelming sense of accumulation.' },
      { id: 'lt-40', front: 'Syndetic List', back: 'A list with conjunctions between each item.\n\nExample: "She packed her bag and her books and her lunch and her coat."\n\nEffect: Can suggest endlessness, monotony, or childlike voice.' },
      { id: 'lt-41', front: 'Declarative Sentence', back: 'A statement that declares a fact or opinion.\n\nExample: "The door was locked."\n\nEffect: Creates authority, certainty, or finality.' },
      { id: 'lt-42', front: 'Interrogative Sentence', back: 'A sentence that asks a question.\n\nExample: "Where had she gone?"\n\nEffect: Creates mystery, engages the reader, or shows a character\'s uncertainty.' },
      { id: 'lt-43', front: 'Exclamatory Sentence', back: 'A sentence that expresses strong emotion, ending with "!"\n\nExample: "The house was on fire!"\n\nEffect: Conveys shock, excitement, fear, or urgency.' },
      { id: 'lt-44', front: 'Minor Sentence / Fragment', back: 'An incomplete sentence used for effect.\n\nExample: "Silence. Complete silence."\n\nEffect: Creates impact, emphasis, or mirrors disruption.' },
      { id: 'lt-45', front: 'Passive Voice', back: 'The subject receives the action rather than performing it.\n\nExample: "The window was broken" (vs. "He broke the window").\n\nEffect: Removes agency, creates mystery about who performed the action, or shifts focus to the victim.' },
      { id: 'lt-46', front: 'Euphemism', back: 'A mild or indirect expression used instead of a harsh or blunt one.\n\nExample: "He passed away" instead of "He died."\n\nEffect: Softens impact, shows sensitivity, or conceals reality.' },
      { id: 'lt-47', front: 'Antithesis', back: 'A contrast of ideas using parallel structure.\n\nExample: "It was the best of times, it was the worst of times." (Dickens)\n\nEffect: Highlights opposition and creates a balanced, memorable rhythm.' },
      { id: 'lt-48', front: 'Colloquial Language', back: 'Informal, everyday language (slang, dialect, casual phrasing).\n\nExample: "He was well gutted about it."\n\nEffect: Creates a realistic, relatable voice. Can show social class or region.' },
      { id: 'lt-49', front: 'Zoomorphism', back: 'Describing a human using animal qualities.\n\nExample: "He prowled the corridors, eyes sharp, jaw set."\n\nEffect: Can suggest predatory behaviour, instinct, or loss of humanity.' },
      { id: 'lt-50', front: 'Cyclical Structure', back: 'When a text ends where it began, returning to the opening image or idea.\n\nEffect: Creates a sense of completion, inevitability, or entrapment. Suggests nothing has changed — or that everything has.' },
    ],
  },
  {
    id: 'grammar-terms',
    title: 'Grammar Terms',
    description: '30 essential grammar terms',
    category: 'Grammar',
    board: 'All',
    cards: [
      { id: 'gt-1', front: 'Noun', back: 'A word that names a person, place, thing, or idea.\n\nTypes: Proper (London), Common (city), Abstract (love), Collective (flock).' },
      { id: 'gt-2', front: 'Verb', back: 'A word that describes an action, state, or occurrence.\n\nTypes: Dynamic (run), Stative (believe), Modal (can, should), Auxiliary (is, have).' },
      { id: 'gt-3', front: 'Adjective', back: 'A word that describes a noun.\n\nExample: "The tall, dark stranger."\n\nComparative: taller. Superlative: tallest.' },
      { id: 'gt-4', front: 'Adverb', back: 'A word that modifies a verb, adjective, or another adverb.\n\nExample: "She ran quickly." "It was extremely cold."\n\nNot all end in -ly: very, well, fast, never.' },
      { id: 'gt-5', front: 'Pronoun', back: 'A word that replaces a noun.\n\nTypes: Personal (I, he, she), Possessive (my, his), Relative (who, which), Demonstrative (this, that).' },
      { id: 'gt-6', front: 'Preposition', back: 'A word that shows the relationship between a noun and another word.\n\nExamples: in, on, at, under, between, through, during.' },
      { id: 'gt-7', front: 'Conjunction', back: 'A word that joins clauses or sentences.\n\nCoordinating: and, but, or, so (FANBOYS)\nSubordinating: because, although, when, if, while.' },
      { id: 'gt-8', front: 'Determiner', back: 'A word that comes before a noun to identify it.\n\nArticles: a, an, the\nDemonstratives: this, that, these, those\nPossessives: my, your, their.' },
      { id: 'gt-9', front: 'Simple Sentence', back: 'One main clause with a subject and verb.\n\nExample: "The dog barked."\n\nEffect: Clear, direct, punchy. Good for impact.' },
      { id: 'gt-10', front: 'Compound Sentence', back: 'Two main clauses joined by a coordinating conjunction (and, but, or, so).\n\nExample: "The sun rose and the birds began to sing."' },
      { id: 'gt-11', front: 'Complex Sentence', back: 'A main clause + one or more subordinate clauses.\n\nExample: "Although it was raining, they went outside."\n\nThe subordinate clause cannot stand alone.' },
      { id: 'gt-12', front: 'Main Clause', back: 'A clause that can stand alone as a complete sentence.\n\nExample: "She laughed." (This makes sense on its own.)' },
      { id: 'gt-13', front: 'Subordinate Clause', back: 'A clause that adds information but cannot stand alone.\n\nExample: "...because she was happy" — needs a main clause.\n\nOften starts with: because, although, when, if, while, who, which.' },
      { id: 'gt-14', front: 'Relative Clause', back: 'A subordinate clause starting with who, which, that, where, whose.\n\nExample: "The teacher, who was new, smiled nervously."\n\nAdds extra information about a noun.' },
      { id: 'gt-15', front: 'Active Voice', back: 'The subject performs the action.\n\nExample: "The cat chased the mouse."\n\nEffect: Direct, clear, dynamic.' },
      { id: 'gt-16', front: 'Subject', back: 'The person or thing performing the action in a sentence.\n\nExample: "The girl ran home." (The girl = subject).' },
      { id: 'gt-17', front: 'Object', back: 'The person or thing receiving the action.\n\nExample: "She kicked the ball." (the ball = object)\n\nDirect object: receives the action. Indirect object: benefits from it.' },
      { id: 'gt-18', front: 'Tense', back: 'When an action takes place.\n\nPast: "She walked." Present: "She walks." Future: "She will walk."\n\nPerfect: "She had walked." Progressive: "She was walking."' },
      { id: 'gt-19', front: 'Apostrophe (Punctuation)', back: 'Used for:\n1. Possession: "the dog\'s bone" / "the dogs\' bones"\n2. Contraction: "don\'t" = "do not"\n\nNEVER for plurals: "apple\'s" is wrong.' },
      { id: 'gt-20', front: 'Semicolon', back: 'Joins two closely related main clauses without a conjunction.\n\nExample: "The rain stopped; the sun came out."\n\nBoth sides must be complete sentences.' },
      { id: 'gt-21', front: 'Colon', back: 'Introduces a list, explanation, or elaboration.\n\nExample: "She had one goal: survival."\n\nThe part before the colon must be a complete sentence.' },
      { id: 'gt-22', front: 'Parenthesis', back: 'Extra information inserted into a sentence using brackets, dashes, or commas.\n\nExample: "My brother — the tall one — is a doctor."\n\nThe sentence should still make sense without it.' },
      { id: 'gt-23', front: 'Ellipsis', back: 'Three dots (...) used to show:\n1. Something has been left out\n2. A trailing off of speech\n3. Suspense or hesitation\n\nExample: "She opened the door and saw..."' },
      { id: 'gt-24', front: 'Clause', back: 'A group of words containing a subject and a verb.\n\nMain clause: can stand alone. Subordinate clause: cannot.\n\nEvery sentence has at least one clause.' },
      { id: 'gt-25', front: 'Phrase', back: 'A group of words that does NOT contain both a subject and a verb.\n\nExamples: "in the garden" (prepositional phrase), "the old house" (noun phrase).' },
      { id: 'gt-26', front: 'Noun Phrase', back: 'A group of words built around a noun.\n\nExample: "the extremely heavy, leather-bound book"\n\nUsing expanded noun phrases adds detail and sophistication to writing.' },
      { id: 'gt-27', front: 'Modal Verb', back: 'A verb that expresses possibility, necessity, or permission.\n\nExamples: can, could, may, might, will, would, shall, should, must.\n\nEffect: "You must leave" is more forceful than "You should leave."' },
      { id: 'gt-28', front: 'Infinitive', back: 'The base form of a verb, usually with "to."\n\nExample: "to run," "to be," "to think."\n\nSplit infinitive: "to boldly go" (adverb between "to" and verb).' },
      { id: 'gt-29', front: 'Participle', back: 'A verb form used as an adjective or to form tenses.\n\nPresent: running, singing (-ing)\nPast: broken, forgotten (-ed/-en)\n\nExample: "The broken vase lay on the floor."' },
      { id: 'gt-30', front: 'Standard English', back: 'The formal, grammatically "correct" form of English used in education, business, and formal writing.\n\nNon-standard: "We was going" → Standard: "We were going."\n\nExpected in exam writing but characters may use non-standard English for realism.' },
    ],
  },
  {
    id: 'christmas-carol-quotes',
    title: 'A Christmas Carol — Key Quotations',
    description: 'Essential quotes for GCSE Literature',
    category: 'Literature',
    board: 'AQA',
    cards: [
      { id: 'cc-1', front: '"Oh! But he was a tight-fisted hand at the grindstone, Scrooge!"', back: 'Stave 1. Introduces Scrooge as miserly and mean. "Tight-fisted" = unwilling to spend. "Grindstone" = relentless, mechanical labour. Dickens establishes Scrooge as everything wrong with Victorian capitalism.' },
      { id: 'cc-2', front: '"Solitary as an oyster"', back: 'Stave 1. Simile showing Scrooge\'s isolation. Oysters are hard-shelled and closed off — like Scrooge. But oysters also contain pearls — hinting at the goodness hidden within.' },
      { id: 'cc-3', front: '"Are there no prisons? Are there no workhouses?"', back: 'Stave 1. Scrooge\'s response to being asked for charity. Rhetorical questions. Shows his Malthusian attitude — he believes the poor deserve punishment, not help. Dickens satirises this Victorian mindset.' },
      { id: 'cc-4', front: '"If they would rather die, they had better do it, and decrease the surplus population"', back: 'Stave 1. Scrooge echoing Thomas Malthus\'s theory. "Surplus population" = the poor are expendable. This is Scrooge at his worst — completely dehumanising the poor. The Ghost of Christmas Present throws this back at him.' },
      { id: 'cc-5', front: '"I wear the chain I forged in life"', back: 'Stave 1. Marley\'s ghost. Metaphor: the chain represents his sins and selfishness. "Forged" = he created it himself. Message: we are responsible for our own moral choices. The chain gets heavier with every selfish act.' },
      { id: 'cc-6', front: '"Mankind was my business"', back: 'Stave 1. Marley\'s ghost. The most important line in the novella. "Business" has a double meaning — Marley now realises that caring for others should have been his real purpose, not making money.' },
      { id: 'cc-7', front: '"A solitary child, neglected by his friends"', back: 'Stave 2. Ghost of Christmas Past shows young Scrooge alone at school. "Solitary" and "neglected" generate sympathy. Explains WHY Scrooge became cold — he was hurt first. Dickens asks the reader to understand, not just judge.' },
      { id: 'cc-8', front: '"Another idol has displaced me... a golden one"', back: 'Stave 2. Belle breaking off the engagement. "Idol" = something worshipped. Money has replaced love. "Golden" — ironic because gold should be precious but here it represents loss.' },
      { id: 'cc-9', front: '"God bless us, every one!"', back: 'Stave 3. Tiny Tim\'s famous line. Inclusive — "every one" means all of society, not just the rich. Tim\'s generosity contrasts with Scrooge\'s selfishness. He blesses even those who have nothing to do with him.' },
      { id: 'cc-10', front: '"If these shadows remain unaltered by the Future, the child will die"', back: 'Stave 3. The Ghost of Christmas Present about Tiny Tim. "Shadows" = visions of what may come. The conditional "if" gives Scrooge a choice — and therefore responsibility. Dickens makes the consequence of inaction personal.' },
      { id: 'cc-11', front: '"This boy is Ignorance. This girl is Want."', back: 'Stave 3. Two wretched children hidden under the Ghost\'s robe. Allegory for society\'s failures. "Beware them both" — Dickens\'s direct message to Victorian readers. Ignorance is the most dangerous because uneducated people cannot help themselves.' },
      { id: 'cc-12', front: '"I will honour Christmas in my heart, and try to keep it all the year"', back: 'Stave 4. Scrooge\'s promise of change. "Honour" = respect and celebrate. "All the year" = not just at Christmas. This transformation is Dickens\'s model for social reform — change must be sustained, not seasonal.' },
      { id: 'cc-13', front: '"He became as good a friend, as good a master, and as good a man, as the good old city knew"', back: 'Stave 5. Tricolon showing Scrooge\'s complete transformation. "Friend, master, man" — personal, professional, moral. Dickens shows that change is possible at any age.' },
    ],
  },
  {
    id: 'jekyll-hyde-quotes',
    title: 'Jekyll and Hyde — Key Quotations',
    description: 'Essential quotes for GCSE Literature',
    category: 'Literature',
    board: 'AQA',
    cards: [
      { id: 'jh-1', front: '"Mr Hyde was pale and dwarfish, he gave an impression of deformity"', back: 'Chapter 1. Hyde\'s appearance reflects Victorian ideas that evil shows physically (physiognomy). "Dwarfish" = smaller, less evolved. "Impression" = people sense something wrong but cannot explain it.' },
      { id: 'jh-2', front: '"Trampled calmly over the child\'s body"', back: 'Chapter 1. Hyde\'s first act of violence. "Trampled" = animalistic, brutal. "Calmly" = the most disturbing word — no remorse. The juxtaposition shows Hyde lacks basic human empathy.' },
      { id: 'jh-3', front: '"If he be Mr Hyde, I shall be Mr Seek"', back: 'Chapter 2. Utterson\'s wordplay. Foreshadows the pursuit of truth. Also echoes "hide and seek" — a child\'s game, but here the stakes are deadly.' },
      { id: 'jh-4', front: '"Man is not truly one, but truly two"', back: 'Chapter 10. Jekyll\'s central revelation. Duality of human nature — good and evil coexist in everyone. Stevenson challenges Victorian hypocrisy: people pretended to be good while hiding their desires.' },
      { id: 'jh-5', front: '"My devil had been long caged, he came out roaring"', back: 'Chapter 10. Jekyll describing Hyde breaking free. "Devil" = religious imagery of evil. "Caged" = repression. "Roaring" = uncontrollable, animalistic. Stevenson suggests repression makes evil stronger.' },
      { id: 'jh-6', front: '"The pleasures which I made haste to seek in my disguise were, as I have said, undignified"', back: 'Chapter 10. Jekyll admits to enjoying Hyde\'s freedom. "Disguise" = Hyde is a mask. "Undignified" = a euphemism — Stevenson lets Victorian readers imagine the worst. The vagueness makes it more disturbing.' },
      { id: 'jh-7', front: '"With ape-like fury"', back: 'Chapter 4. Hyde murdering Sir Danvers Carew. Simile comparing Hyde to a primate. Darwin\'s theory of evolution was controversial — Hyde represents devolution, a return to animal instinct.' },
      { id: 'jh-8', front: '"The door... which was equipped with neither bell nor knocker, was blistered and distained"', back: 'Chapter 1. The door to Jekyll\'s laboratory. Symbolises the hidden, shameful side of respectable life. "Blistered and distained" = decayed, neglected — like the morality it conceals.' },
      { id: 'jh-9', front: '"I learned to recognise the thorough and primitive duality of man"', back: 'Chapter 10. "Primitive" = primal, basic. "Thorough" = complete, inescapable. Jekyll discovers that duality is not a flaw — it is fundamental to human nature.' },
      { id: 'jh-10', front: '"I was slowly losing hold of my original and better self"', back: 'Chapter 10. Jekyll losing control. "Original" = the real, authentic self. "Better" = moral judgement. "Slowly" = gradual, creeping loss — more frightening than sudden change.' },
    ],
  },
  {
    id: 'inspector-calls-quotes',
    title: 'An Inspector Calls — Key Quotations',
    description: 'Essential quotes for GCSE Literature',
    category: 'Literature',
    board: 'AQA',
    cards: [
      { id: 'ic-1', front: '"We are members of one body. We are responsible for each other."', back: 'Act 3. The Inspector\'s final speech. "One body" = organic metaphor for society. Directly states Priestley\'s socialist message. Echoes Christian teaching — deliberate, as the Birlings claim to be moral.' },
      { id: 'ic-2', front: '"If men will not learn that lesson, then they will be taught it in fire and blood and anguish"', back: 'Act 3. The Inspector\'s warning. Written in 1945, set in 1912 — Priestley\'s audience knew the "fire and blood" meant WWI and WWII. Tricolon builds to "anguish." Still relevant today.' },
      { id: 'ic-3', front: '"The Titanic — unsinkable, absolutely unsinkable"', back: 'Act 1. Birling\'s confident prediction. Dramatic irony — the audience knows the Titanic sank. Undermines everything Birling says. If he is wrong about this, he is wrong about everything.' },
      { id: 'ic-4', front: '"A man has to make his own way — has to look after himself"', back: 'Act 1. Birling\'s capitalist philosophy. Direct opposite of the Inspector\'s message. "His own" and "himself" = entirely selfish. Birling sees community as weakness.' },
      { id: 'ic-5', front: '"But these girls aren\'t cheap labour — they\'re people"', back: 'Act 1. Sheila challenging her father. Shows her growing awareness. "People" = asserting the workers\' humanity. This is the beginning of Sheila\'s moral awakening.' },
      { id: 'ic-6', front: '"I\'ll never, never do it again to anybody"', back: 'Act 2. Sheila\'s response after hearing about her role in Eva\'s death. Repetition of "never" = genuine remorse. Contrast with her parents who refuse to accept blame. Sheila represents hope for change.' },
      { id: 'ic-7', front: '"You\'re not the kind of father a chap could go to when he\'s in trouble"', back: 'Act 2. Eric to Birling. Reveals the family\'s dysfunction. Birling is a failure as a father — too busy with business to connect with his son. Priestley shows that capitalism damages families.' },
      { id: 'ic-8', front: '"I was in that state when a chap easily turns nasty"', back: 'Act 3. Eric about the night he forced himself on Eva. "That state" = drunk. Euphemism for assault. Eric takes some responsibility but also deflects it. Priestley shows how privilege enables harm.' },
      { id: 'ic-9', front: '"She was a pretty, lively sort of girl... and she needed not only money but advice, sympathy, friendliness"', back: 'Act 2. Gerald describing Eva/Daisy. Shows he genuinely cared — but also that his "care" came from a position of power. He rescued her but also controlled her.' },
      { id: 'ic-10', front: '"The girl\'s dead and we all helped to kill her"', back: 'Act 3. The Inspector\'s blunt accusation. Collective guilt. "We all" = no one can escape responsibility. The verb "kill" — not "contributed to her death" — is deliberately shocking.' },
      { id: 'ic-11', front: '"I\'m ashamed of you as well — yes, both of you"', back: 'Act 3. Sheila to her parents. Generational reversal — the child judges the parents. "Ashamed" = strong moral condemnation. Priestley positions the younger generation as the moral future.' },
      { id: 'ic-12', front: '"Everything\'s all right now, Sheila. What about this ring?"', back: 'Act 3. Gerald trying to return to normal. The ring symbolises their superficial relationship. Gerald has learned nothing. Priestley shows that some people will never change.' },
    ],
  },
  {
    id: 'edexcel-relationships-poetry',
    title: 'Edexcel Poetry Anthology — Relationships',
    description: '15 poems from the Edexcel Relationships poetry collection with key quotes, themes, and techniques',
    category: 'Literature',
    board: 'Edexcel',
    cards: [
      { id: 'erp-1', front: 'La Belle Dame Sans Merci — John Keats', back: 'Key quote: "I met a lady in the meads, / Full beautiful — a faery\'s child"\n\nThemes: Destructive love, power imbalance, enchantment, isolation.\n\nTechniques: Ballad form, archaic language, supernatural imagery, cyclical structure (returns to the pale knight on the hillside).\n\nCompare with: She Walks in Beauty (idealised beauty), Neutral Tones (love that destroys).' },
      { id: 'erp-2', front: 'A Child to his Sick Grandfather — Joanna Baillie', back: 'Key quote: "Grand-dad, they say you\'re old and frail"\n\nThemes: Family love, ageing, innocence vs experience, mortality.\n\nTechniques: Child speaker (naive voice), direct address, contrast between youth and age, simple diction reflecting the child\'s perspective.\n\nCompare with: Nettles (parent-child love), My Father Would Not Show Us (family distance).' },
      { id: 'erp-3', front: 'She Walks in Beauty — Lord Byron', back: 'Key quote: "She walks in beauty, like the night / Of cloudless climes and starry skies"\n\nThemes: Idealised beauty, admiration, harmony of inner and outer beauty.\n\nTechniques: Simile, regular metre (iambic tetrameter), antithesis of dark and light, enjambment creating flowing admiration.\n\nCompare with: La Belle Dame Sans Merci (beauty as power), Sonnet 43 (adoration).' },
      { id: 'erp-4', front: 'A Complaint — William Wordsworth', back: 'Key quote: "There is a change — and I am poor"\n\nThemes: Loss of love, emotional dependency, change, grief.\n\nTechniques: Extended metaphor of a fountain (love as a water source that dries up), caesura reflecting emotional disruption, shift from abundance to emptiness.\n\nCompare with: Neutral Tones (love ended), One Flesh (emotional distance).' },
      { id: 'erp-5', front: 'Neutral Tones — Thomas Hardy', back: 'Key quote: "We stood by a pond that winter day, / And the sun was white, as though chidden of God"\n\nThemes: End of love, bitterness, memory, emotional deadness.\n\nTechniques: Pathetic fallacy (bleached landscape), colour symbolism (white = lifeless), cyclical structure, monosyllabic words creating flat, defeated tone.\n\nCompare with: A Complaint (love lost), One Flesh (emotional distance).' },
      { id: 'erp-6', front: 'My Last Duchess — Robert Browning', back: 'Key quote: "That\'s my last Duchess painted on the wall, / Looking as if she were alive"\n\nThemes: Power and control, jealousy, possession, toxic masculinity, objectification.\n\nTechniques: Dramatic monologue, enjambment (Duke\'s controlling speech), iambic pentameter, sinister undertone — "I gave commands; / Then all smiles stopped together."\n\nCompare with: La Belle Dame Sans Merci (power in love), Valentine (unconventional love).' },
      { id: 'erp-7', front: 'Sonnet 43 — Elizabeth Barrett Browning', back: 'Key quote: "How do I love thee? Let me count the ways"\n\nThemes: Unconditional love, devotion, spiritual love, eternal love.\n\nTechniques: Petrarchan sonnet form, anaphora ("I love thee"), religious imagery ("Grace," "saints"), hyperbole suggesting love beyond measurement.\n\nCompare with: She Walks in Beauty (admiration), i wanna be yours (devotion).' },
      { id: 'erp-8', front: '1st Date — She / 1st Date — He — Wendy Cope', back: 'Key quote (She): "I can\'t believe I\'ve met someone so nice"\nKey quote (He): "She\'s absolutely gorgeous"\n\nThemes: New love, excitement, nervousness, contrasting perspectives.\n\nTechniques: Dual perspective (two companion poems), colloquial language, humour, internal monologue revealing insecurity beneath confidence.\n\nCompare with: Valentine (modern love), Love\'s Dog (conflicting emotions in love).' },
      { id: 'erp-9', front: 'Valentine — Carol Ann Duffy', back: 'Key quote: "I give you an onion. / It is a moon wrapped in brown paper"\n\nThemes: Unconventional love, honesty about relationships, love as painful, rejection of cliché.\n\nTechniques: Extended metaphor (onion = love), free verse, imperative verbs ("Take it"), monosyllabic final line — "Lethal" — showing love\'s danger.\n\nCompare with: Sonnet 43 (contrasting view of love), Love\'s Dog (love\'s contradictions).' },
      { id: 'erp-10', front: 'One Flesh — Elizabeth Jennings', back: 'Key quote: "Lying apart now, each in a separate bed"\n\nThemes: Long-term love, emotional distance, ageing, loss of passion, memory.\n\nTechniques: Enjambment, religious allusion ("one flesh" from Genesis), oxymoron of closeness and distance, reflective tone, third-person observation of her own parents.\n\nCompare with: Neutral Tones (emotional death), A Complaint (love changed).' },
      { id: 'erp-11', front: 'i wanna be yours — John Cooper Clarke', back: 'Key quote: "I wanna be your electric meter / I will not run out"\n\nThemes: Devotion, desire, total commitment, modern love.\n\nTechniques: Extended metaphor (domestic objects = devotion), repetition ("I wanna be your"), lack of punctuation and capitalisation (informal, urgent tone), metaphors escalate from mundane to passionate.\n\nCompare with: Sonnet 43 (total devotion), Valentine (modern love poem).' },
      { id: 'erp-12', front: 'Love\'s Dog — Jen Hadfield', back: 'Key quote: "What I love about love is its diamond blaze. / What I hate about love is its diamond blaze."\n\nThemes: Contradictions of love, joy and pain coexisting, duality of emotion.\n\nTechniques: Anaphora ("What I love / What I hate"), antithesis, list structure, repeated syntactic pattern highlighting love\'s paradoxes.\n\nCompare with: Valentine (honest about love\'s pain), 1st Date (excitement of love).' },
      { id: 'erp-13', front: 'Nettles — Vernon Scannell', back: 'Key quote: "My son aged three fell in the nettle bed. / \'Bed\' seemed a word of comfort"\n\nThemes: Parental love, protectiveness, futility of shielding children, military imagery.\n\nTechniques: Extended metaphor (nettles = threats to children), military lexis ("regiment," "fierce parade," "fallen dead"), sonnet-like 14 lines, irony of "bed" as comfort vs pain.\n\nCompare with: The Manhunt (love and suffering), A Child to his Sick Grandfather (family bonds).' },
      { id: 'erp-14', front: 'The Manhunt — Simon Armitage', back: 'Key quote: "After the first phase, / after passionate nights and intimate days"\n\nThemes: Love and trauma, PTSD, physical and emotional scars, patience, intimacy after war.\n\nTechniques: Extended metaphor (body as damaged landscape), couplets (togetherness), half-rhyme (discord), anatomical language tracing the body, wife\'s perspective showing love as slow recovery.\n\nCompare with: Nettles (love amid pain), One Flesh (physical/emotional distance).' },
      { id: 'erp-15', front: 'My Father Would Not Show Us — Ingrid de Kok', back: 'Key quote: "My father would not show us his dying"\n\nThemes: Family relationships, grief, distance, masculinity and vulnerability, death.\n\nTechniques: Negative construction ("would not show"), contrast between what father hides and what speaker reveals, enjambment mirroring life flowing away, restrained tone reflecting the father\'s own restraint.\n\nCompare with: A Child to his Sick Grandfather (family and mortality), One Flesh (emotional distance in family).' },
    ],
  },
  {
    id: 'edexcel-conflict-poetry',
    title: 'Edexcel Poetry Anthology — Conflict',
    description: '15 poems from the Edexcel Conflict poetry collection with key quotes, themes, and techniques',
    category: 'Literature',
    board: 'Edexcel',
    cards: [
      { id: 'ecp-1', front: 'A Poison Tree — William Blake', back: 'Key quote: "I was angry with my friend: / I told my wrath, my wrath did end"\n\nThemes: Suppressed anger, revenge, duplicity, consequences of bottled emotion.\n\nTechniques: Extended metaphor (anger as a growing tree), antithesis (friend vs foe), simple AABB rhyme (nursery-rhyme tone = sinister), biblical allusion (Tree of Knowledge, Garden of Eden).\n\nCompare with: Catrin (personal conflict), Half-caste (anger expressed openly).' },
      { id: 'ecp-2', front: 'The Destruction of Sennacherib — Lord Byron', back: 'Key quote: "The Assyrian came down like the wolf on the fold, / And his cohorts were gleaming in purple and gold"\n\nThemes: Power of God vs power of man, futility of war, destruction of armies.\n\nTechniques: Anapaestic metre (galloping rhythm = cavalry charge), simile ("like the wolf on the fold"), colour imagery (purple/gold = pride; then death), biblical source (II Kings).\n\nCompare with: The Charge of the Light Brigade (doomed military action), Exposure (war\'s destruction).' },
      { id: 'ecp-3', front: 'Extract from The Prelude — William Wordsworth', back: 'Key quote: "A huge peak, black and huge, / As if with voluntary power instinct, / Upreared its head"\n\nThemes: Man vs nature, power of nature, loss of innocence, sublime terror.\n\nTechniques: Blank verse, personification of the mountain, contrast between confidence and fear, volta when the peak appears, enjambment creating momentum of fear.\n\nCompare with: Exposure (nature as hostile force), A Poison Tree (internal conflict).' },
      { id: 'ecp-4', front: 'The Man He Killed — Thomas Hardy', back: 'Key quote: "Yes; quaint and curious war is! / You shoot a fellow down / You\'d treat, if met where any bar is"\n\nThemes: Futility of war, class and conflict, shared humanity of enemies, senselessness of killing.\n\nTechniques: Dramatic monologue, colloquial language, caesura and dashes (hesitation = guilt), ironic understatement ("quaint and curious"), regular ballad metre (simple form for complex ideas).\n\nCompare with: What Were They Like? (questioning war), Exposure (soldiers\' suffering).' },
      { id: 'ecp-5', front: 'Cousin Kate — Christina Rossetti', back: 'Key quote: "Why did a great lord find me out, / And praise my flaxen hair?"\n\nThemes: Betrayal, sexual exploitation, class and gender, fallen women, power imbalance.\n\nTechniques: Ballad form, rhetorical questions, contrast between speaker and Kate, bitter tone, the child as "gift" vs "shame," defiant final stanza.\n\nCompare with: My Last Duchess (power and gender), The Class Game (class conflict).' },
      { id: 'ecp-6', front: 'Exposure — Wilfred Owen', back: 'Key quote: "Our brains ache, in the merciless iced east winds that knive us"\n\nThemes: Suffering of soldiers, futility of war, nature as enemy, hopelessness.\n\nTechniques: Para-rhyme (half-rhyme creates unease), personification of wind, sibilance, repeated refrain "But nothing happens" (anti-climax = pointlessness), present tense (immediacy).\n\nCompare with: The Charge of the Light Brigade (war experience), The Destruction of Sennacherib (war\'s devastation).' },
      { id: 'ecp-7', front: 'The Charge of the Light Brigade — Alfred, Lord Tennyson', back: 'Key quote: "Into the valley of Death / Rode the six hundred"\n\nThemes: Bravery, obedience, futility of war, honour, military blunder.\n\nTechniques: Dactylic metre (galloping rhythm), repetition ("six hundred"), biblical allusion ("valley of Death" = Psalm 23), anaphora ("Cannon to right... left... behind"), heroic tone despite tragedy.\n\nCompare with: The Destruction of Sennacherib (doomed forces), Exposure (contrasting tone about war).' },
      { id: 'ecp-8', front: 'Half-caste — John Agard', back: 'Key quote: "Explain yuself / wha yu mean / when yu say half-caste"\n\nThemes: Racial identity, prejudice, challenging stereotypes, pride, anger at ignorance.\n\nTechniques: Phonetic spelling (Caribbean dialect), imperative verbs ("Explain yuself"), extended metaphors (Picasso, Tchaikovsky), humour and sarcasm to expose absurdity, lack of punctuation (defiance of convention).\n\nCompare with: No Problem (racial prejudice), The Class Game (identity and prejudice).' },
      { id: 'ecp-9', front: 'Catrin — Gillian Clarke', back: 'Key quote: "I can remember you, child, / As I stood in a hot, white room"\n\nThemes: Parent-child conflict, love and separation, the struggle for independence, enduring bond.\n\nTechniques: Extended metaphor ("the tight, red rope" = umbilical cord and ongoing connection), two-stanza structure (birth / present day), enjambment, oxymoron of love and conflict ("our first fierce confrontation").\n\nCompare with: Nettles (from Relationships — parent-child love), A Poison Tree (personal conflict).' },
      { id: 'ecp-10', front: 'War Photographer — Satyamurti', back: 'Key quote: "The next one shows a boy / about his age"\n\nThemes: Impact of war on civilians, desensitisation, guilt, distance between war zones and comfortable life.\n\nTechniques: Third-person narrator, contrast between domestic comfort and war zone, child\'s perspective, understatement, the photograph as a bridge between two worlds.\n\nCompare with: Poppies (impact of war at home), What Were They Like? (civilian suffering).' },
      { id: 'ecp-11', front: 'Belfast Confetti — Ciaran Carson', back: 'Key quote: "Suddenly as the riot squad moved in it was raining exclamation marks!"\n\nThemes: The Troubles in Northern Ireland, urban conflict, confusion, language as violence.\n\nTechniques: Extended metaphor (punctuation as weaponry — "nuts, bolts, nails" become "exclamation marks"), fragmented syntax mirrors chaos, rhetorical questions showing disorientation, street names as labyrinth.\n\nCompare with: Exposure (being trapped in conflict), Poppies (personal impact of war).' },
      { id: 'ecp-12', front: 'The Class Game — Mary Casey', back: 'Key quote: "How can you tell what class I\'m from? / I can tell what class you\'re from"\n\nThemes: Class conflict, identity, prejudice, pride in working-class roots.\n\nTechniques: Direct address, rhetorical questions, phonetic spelling of accent, contrast between "posh" and working-class markers, defiant and confrontational tone, listing.\n\nCompare with: Half-caste (identity and prejudice), Cousin Kate (class and power).' },
      { id: 'ecp-13', front: 'Poppies — Jane Weir', back: 'Key quote: "I traced the rims of his poppies / and leaned against the war memorial"\n\nThemes: Mother\'s grief, loss, conflict\'s impact on families, memory, letting go.\n\nTechniques: Sensory imagery (touch, texture), domestic and military language juxtaposed, symbolism of poppies, time shifts between past and present, first-person maternal voice.\n\nCompare with: War Photographer (impact of conflict), Catrin (parent-child bond).' },
      { id: 'ecp-14', front: 'No Problem — Benjamin Zephaniah', back: 'Key quote: "I am not de problem / But I bear de brunt"\n\nThemes: Racism, resilience, identity, Black British experience, defiance.\n\nTechniques: Phonetic spelling (Caribbean dialect), repetition ("I am not de problem"), direct address, reggae-influenced rhythm, positive and assertive tone despite injustice.\n\nCompare with: Half-caste (racial identity), The Class Game (fighting prejudice).' },
      { id: 'ecp-15', front: 'What Were They Like? — Denise Levertov', back: 'Key quote: "Did the people of Viet Nam / use lanterns of stone?"\n\nThemes: Vietnam War, destruction of culture, loss of identity, anti-war protest.\n\nTechniques: Q&A structure (questions then answers), past tense ("It is not remembered"), contrast between cultural beauty and destruction, elegiac tone, numbering dehumanises (like a report).\n\nCompare with: War Photographer (civilian suffering), The Man He Killed (questioning war).' },
    ],
  },
  {
    id: 'edexcel-igcse-poetry',
    title: 'Edexcel IGCSE Poetry Anthology',
    description: '16 poems from the Edexcel IGCSE anthology with key quotes, themes, and techniques',
    category: 'Literature',
    board: 'Edexcel',
    cards: [
      { id: 'eig-1', front: 'If-- — Rudyard Kipling', back: 'Key quote: "If you can keep your head when all about you / Are losing theirs and blaming it on you"\n\nThemes: Stoicism, masculinity, moral integrity, resilience, self-control.\n\nTechniques: Anaphora ("If you can"), conditional structure (entire poem is one sentence), second-person address ("you"), iambic pentameter, the final reward — "you\'ll be a Man, my son!" — capitalised "Man" as ideal.\n\nCompare with: Do not go gentle (defiance), Prayer Before Birth (what life demands).' },
      { id: 'eig-2', front: 'Prayer Before Birth — Louis MacNeice', back: 'Key quote: "I am not yet born; O hear me"\n\nThemes: Fear of the modern world, loss of identity, plea for protection, corruption of innocence.\n\nTechniques: Dramatic monologue (unborn child speaks), anaphora ("I am not yet born"), lines get longer (growing dread), imperative pleas, final short line "Let them not make me a stone" — fear of dehumanisation.\n\nCompare with: If-- (preparing for life), Half-past Two (child\'s perspective).' },
      { id: 'eig-3', front: 'Blessing — Imtiaz Dharker', back: 'Key quote: "The skin cracks like a pod. / There never is enough water"\n\nThemes: Poverty, water as precious resource, community, joy in scarcity, spiritual blessing.\n\nTechniques: Simile ("cracks like a pod"), onomatopoeia ("splash," "rush"), enjambment (flowing like water), short opening stanza (drought) vs long third stanza (abundance), religious connotation of "blessing."\n\nCompare with: Search For My Tongue (cultural identity), Poem at Thirty-Nine (what we value).' },
      { id: 'eig-4', front: 'Search For My Tongue — Sujata Bhatt', back: 'Key quote: "You ask me what I mean by saying I have lost my tongue"\n\nThemes: Cultural identity, bilingualism, mother tongue vs adopted language, belonging.\n\nTechniques: Extended metaphor (tongue = language and identity), Gujarati script in the middle section, the mother tongue "grows back" like a plant — organic imagery, direct address, code-switching.\n\nCompare with: Half-caste (identity and language), Blessing (cultural roots).' },
      { id: 'eig-5', front: 'Half-past Two — U. A. Fanthorpe', back: 'Key quote: "He knew a lot of time: he knew Gettinguptime, Timeyougotobed time"\n\nThemes: Childhood innocence, adult authority, time as abstract concept, imagination.\n\nTechniques: Compound words ("Gettinguptime") reflecting child\'s understanding, third person, contrast between child\'s fluid time and adult clock-time, the child escapes "into the forever of not-being-there."\n\nCompare with: Piano (childhood memory), Hide and Seek (child\'s experience).' },
      { id: 'eig-6', front: 'Piano — D. H. Lawrence', back: 'Key quote: "Softly, in the dusk, a woman is singing to me; / Taking me back down the vista of years"\n\nThemes: Nostalgia, childhood, memory, loss of innocence, the power of music.\n\nTechniques: Sibilance ("softly," "singing"), sensory imagery, enjambment, contrast between present (woman singing) and past (mother at piano), the speaker "weeps like a child" — unable to resist memory.\n\nCompare with: Poem at Thirty-Nine (remembering a parent), Half-past Two (childhood perspective).' },
      { id: 'eig-7', front: 'Hide and Seek — Vernon Scannell', back: 'Key quote: "Call out. Call out. / The bushes hold their breath"\n\nThemes: Childhood games, isolation, abandonment, loss of innocence, growing up.\n\nTechniques: Second-person address ("you"), imperative verbs, personification ("bushes hold their breath"), shift from excitement to fear, the child is "found" too late — metaphor for being left behind.\n\nCompare with: Half-past Two (childhood experience), Piano (innocence and loss).' },
      { id: 'eig-8', front: 'Sonnet 116 — William Shakespeare', back: 'Key quote: "Let me not to the marriage of true minds / Admit impediments"\n\nThemes: Eternal love, constancy, love\'s endurance through hardship and time.\n\nTechniques: Shakespearean sonnet (ABAB CDCD EFEF GG), metaphor ("star to every wandering bark" = guiding light), personification of Time with "his bending sickle," negative definitions (love is defined by what it is NOT), final couplet as logical proof.\n\nCompare with: La Belle Dame sans Merci (contrasting love), Do not go gentle (defiance).' },
      { id: 'eig-9', front: 'La Belle Dame sans Merci — John Keats', back: 'Key quote: "O what can ail thee, knight-at-arms, / Alone and palely loitering?"\n\nThemes: Destructive love, enchantment, isolation, supernatural power, death-like state.\n\nTechniques: Ballad form, archaic diction, supernatural imagery ("faery\'s child"), cyclical structure, the knight is left "On the cold hill\'s side" — stripped of vitality.\n\nCompare with: Sonnet 116 (contrasting view of love), My Last Duchess (love and power).' },
      { id: 'eig-10', front: 'Poem at Thirty-Nine — Alice Walker', back: 'Key quote: "How I miss my father. / I wish he had not been / so tired"\n\nThemes: Grief, father-daughter relationship, inheritance of values, growing into a parent\'s likeness.\n\nTechniques: Free verse, short lines (reflective, measured tone), repetition ("He taught me"), enjambment, present tense mixed with past (father lives on through her), celebratory ending — "He would have grown / to admire / the woman I\'ve become."\n\nCompare with: Piano (remembering a parent), Half-past Two (adult reflecting on childhood).' },
      { id: 'eig-11', front: 'War Photographer — Carol Ann Duffy', back: 'Key quote: "In his dark room he is finally alone / with spools of suffering set out in ordered rows"\n\nThemes: War\'s impact, guilt, desensitisation of society, the gap between conflict and comfort.\n\nTechniques: Sibilance ("spools of suffering"), regular stanzas (photographer imposing order on chaos), contrast between "Rural England" and war zones, metaphor — "a stranger\'s features / faintly start to twist before his eyes" — the image developing mirrors guilt emerging.\n\nCompare with: The Tyger (questioning creation/destruction), Do not go gentle (defiance against suffering).' },
      { id: 'eig-12', front: 'The Tyger — William Blake', back: 'Key quote: "Tyger Tyger, burning bright, / In the forests of the night"\n\nThemes: Creation, good vs evil, awe, the sublime, questioning God.\n\nTechniques: Trochaic metre (hammering rhythm = the forge), rhetorical questions throughout (no answers = mystery), symbolism (Tyger = power/evil, Lamb = innocence/good), alliteration, industrial imagery ("hammer," "chain," "furnace").\n\nCompare with: Prayer Before Birth (questioning existence), Blessing (spiritual themes).' },
      { id: 'eig-13', front: 'My Last Duchess — Robert Browning', back: 'Key quote: "She had / A heart — how shall I say? — too soon made glad"\n\nThemes: Power, control, jealousy, patriarchy, art and possession.\n\nTechniques: Dramatic monologue, iambic pentameter with enjambment (Duke\'s conversational control), the pause "how shall I say?" = calculated menace, the painting as ultimate possession — "the curtain I have drawn for you."\n\nCompare with: Sonnet 116 (contrasting views of love), The Tyger (power).' },
      { id: 'eig-14', front: 'Half-caste — John Agard', back: 'Key quote: "Explain yuself / wha yu mean / when yu say half-caste"\n\nThemes: Racial identity, challenging prejudice, pride, absurdity of racial labels.\n\nTechniques: Phonetic Caribbean dialect, imperative verbs, extended metaphors (Picasso\'s art, Tchaikovsky\'s music, English weather), humour and irony to dismantle prejudice, lack of standard punctuation = defiance.\n\nCompare with: Search For My Tongue (identity and language), The Tyger (challenging assumptions).' },
      { id: 'eig-15', front: 'Do not go gentle into that good night — Dylan Thomas', back: 'Key quote: "Do not go gentle into that good night. / Rage, rage against the dying of the light"\n\nThemes: Death, defiance, father-son relationship, fighting against mortality.\n\nTechniques: Villanelle form (repeated refrains = obsessive plea), metaphor (night = death, light = life), imperative verbs ("rage"), catalogue of men (wise, good, wild, grave) who all resist death, final stanza addressed directly to his father.\n\nCompare with: Remember (attitudes to death), If-- (strength in adversity).' },
      { id: 'eig-16', front: 'Remember — Christina Rossetti', back: 'Key quote: "Remember me when I am gone away, / Gone far away into the silent land"\n\nThemes: Death, memory, love, letting go, acceptance.\n\nTechniques: Petrarchan sonnet, euphemism ("gone away," "silent land" = death), volta at line 9 (shift from "remember" to "forget"), imperative softening to permission — "Better by far you should forget and smile / Than that you should remember and be sad."\n\nCompare with: Do not go gentle (contrasting attitude to death), Poem at Thirty-Nine (memory of loved ones).' },
    ],
  },
  {
    id: 'edexcel-paper1-key-terms',
    title: 'Edexcel Paper 1: Core Terms & Forms',
    description: '20 essential terms for Edexcel English Language Paper 1 (Fiction and Imaginative Writing / Non-Fiction and Transactional Writing)',
    category: 'Exam Skills',
    board: 'Edexcel',
    cards: [
      { id: 'ep1-1', front: 'Evaluation (Edexcel Definition)', back: 'Making a judgement about a text supported by evidence. In Edexcel Paper 1, you must evaluate how effectively a writer achieves their purpose.\n\nStructure: State your judgement, provide a quote as evidence, analyse technique and effect, link back to your evaluative point.\n\nKey phrase starters: "The writer effectively...", "This is convincing because...", "This is less successful because..."' },
      { id: 'ep1-2', front: 'Article (Transactional Writing)', back: 'A piece of writing for a newspaper or magazine.\n\nFeatures: Headline, optional subheading, opening hook, paragraphed body, formal or semi-formal register depending on audience.\n\nTips: Use rhetorical devices (tricolon, rhetorical questions, direct address). Include a strong conclusion that circles back to your opening.' },
      { id: 'ep1-3', front: 'Blog Post (Transactional Writing)', back: 'An informal, opinion-based piece of online writing.\n\nFeatures: Engaging title, personal voice (first person), conversational tone, short paragraphs, direct address to readers.\n\nTips: Can include humour, anecdotes, and rhetorical questions. More relaxed than an article but still needs a clear structure and persuasive techniques.' },
      { id: 'ep1-4', front: 'Formal Letter (Transactional Writing)', back: 'A letter to an official audience (e.g., headteacher, council, MP).\n\nFormat: Your address (top right), recipient\'s address (left), date, "Dear Sir/Madam" or "Dear Mr/Mrs X," formal sign-off ("Yours faithfully" if unknown, "Yours sincerely" if named).\n\nTips: Formal register, clear paragraphs with topic sentences, measured but persuasive tone.' },
      { id: 'ep1-5', front: 'Report (Transactional Writing)', back: 'A formal, factual document presenting findings or recommendations.\n\nFeatures: Title, optional subheadings, introduction stating purpose, paragraphed body with evidence, conclusion with recommendations.\n\nTips: Impersonal tone ("It was found that..."), factual language, logical structure. Avoid emotional language — let evidence speak.' },
      { id: 'ep1-6', front: 'Review (Transactional Writing)', back: 'A critical assessment of a product, event, book, or experience.\n\nFeatures: Introduction (what you are reviewing), balanced analysis (positives and negatives), personal opinion supported by detail, recommendation.\n\nTips: Use descriptive and evaluative language. Engage the reader with humour or vivid detail. Give a clear verdict.' },
      { id: 'ep1-7', front: 'Speech (Transactional Writing)', back: 'A written text designed to be spoken aloud to an audience.\n\nFeatures: Direct address ("Ladies and gentlemen"), rhetorical questions, tricolon, anecdotes, emotive language, repetition for emphasis.\n\nTips: Write for the ear, not the eye. Use short sentences for impact. Include a powerful opening and a memorable closing line.' },
      { id: 'ep1-8', front: 'Email (Transactional Writing)', back: 'A digital message, usually semi-formal or formal depending on audience.\n\nFormat: To/From/Subject line, greeting ("Dear..." or "Hi..."), paragraphed body, sign-off.\n\nTips: Match register to audience. Be concise and purposeful. Professional emails use formal register; emails to peers can be semi-formal.' },
      { id: 'ep1-9', front: 'Guide (Transactional Writing)', back: 'An informative text giving advice or instructions.\n\nFeatures: Title, subheadings, numbered or bulleted points, imperative verbs ("Visit...", "Make sure you..."), direct address.\n\nTips: Clear, logical structure. Informative but engaging. Can use a friendly, encouraging tone depending on audience.' },
      { id: 'ep1-10', front: 'Archaic Vocabulary (19th-Century Feature)', back: 'Old-fashioned words no longer in common use.\n\nExamples: "hitherto" (until now), "whence" (from where), "ere" (before), "betwixt" (between), "forsooth" (indeed).\n\nExam tip: When analysing 19th-century texts, note how archaic vocabulary creates a formal, distant, or elevated tone. Explain what the word means and its effect.' },
      { id: 'ep1-11', front: 'Formal Register (19th-Century Feature)', back: 'A level of language characterised by complex sentences, sophisticated vocabulary, and an impersonal or elevated tone.\n\n19th-century texts often use formal register even in fiction. Look for: long subordinate clauses, Latinate vocabulary, passive constructions.\n\nContrast with modern informal register to show your understanding of context.' },
      { id: 'ep1-12', front: 'Periodic Sentence (19th-Century Feature)', back: 'A long sentence where the main clause is delayed until the end, building suspense or emphasis.\n\nExample: "Despite the rain, the cold, the endless miles of mud through which they trudged, they arrived."\n\nEffect: Creates anticipation. Common in 19th-century prose. Contrasts with modern preference for short, direct sentences.' },
      { id: 'ep1-13', front: 'AO1 — Edexcel English Language', back: 'Read and understand a range of texts. Select and synthesise evidence from different texts.\n\nWhat this means: Identify relevant information, use short embedded quotations, show you understand explicit and implicit meanings.\n\nKey skill: PEE/PEA paragraphs with precise evidence selection.' },
      { id: 'ep1-14', front: 'AO2 — Edexcel English Language', back: 'Explain, comment on and analyse how writers use language and structure to achieve effects and influence readers, using relevant subject terminology.\n\nWhat this means: Identify techniques, analyse their effect on the reader, use correct terminology (but only when it adds to your analysis).\n\nKey skill: "The writer uses [technique] to [effect], which suggests [interpretation]."' },
      { id: 'ep1-15', front: 'AO4 — Edexcel English Language', back: 'Evaluate texts critically and support this with appropriate textual references.\n\nWhat this means: Make a judgement about how effectively a writer achieves their purpose. "How far do you agree?" questions require balanced evaluation.\n\nKey skill: Sustained evaluative commentary — not just analysis, but judgement of effectiveness.' },
      { id: 'ep1-16', front: 'Command Word: "Evaluate"', back: 'Make a judgement about effectiveness. Say HOW WELL the writer achieves something, not just what they do.\n\nApproach: "The writer effectively/convincingly/powerfully [does X] through [technique], which [effect on reader]. This is successful because..."\n\nAvoid: Simply identifying techniques without judging their impact.' },
      { id: 'ep1-17', front: 'Command Word: "Analyse"', back: 'Examine language and/or structure in detail, explaining effects on the reader.\n\nApproach: Quote > Identify technique > Explain effect > Explore deeper meaning. Go beyond surface-level observations.\n\nAvoid: Feature-spotting without explanation. Always answer: "So what? Why does this matter?"' },
      { id: 'ep1-18', front: 'Command Word: "Explain"', back: 'Make your understanding clear with supporting evidence.\n\nApproach: State your point clearly, support with a quotation, develop your explanation of what it shows or suggests.\n\nDifference from "analyse": Less focus on technique names, more focus on meaning and understanding.' },
      { id: 'ep1-19', front: 'Command Word: "How does the writer..."', back: 'Focus on the writer\'s methods and choices — language, structure, form.\n\nApproach: Always discuss the writer as a craftsperson making deliberate choices. Use phrases like "The writer chooses to...", "By using..., the writer creates..."\n\nAvoid: Retelling the story. Focus on HOW, not WHAT.' },
      { id: 'ep1-20', front: 'Command Word: "To what extent do you agree?"', back: 'Requires an evaluative, balanced response. You can mostly agree, mostly disagree, or partially agree.\n\nApproach: State your position, support with evidence, consider alternative interpretations. Sustain your argument throughout.\n\nTip: The strongest answers show nuance — "While the writer does X effectively, the use of Y is less convincing because..."' },
    ],
  },
  {
    id: 'edexcel-paper2-key-terms',
    title: 'Edexcel Paper 2: Core Terms & Techniques',
    description: '20 essential terms for Edexcel English Language Paper 2 (Non-Fiction and Transactional Writing / Poetry and Prose)',
    category: 'Exam Skills',
    board: 'Edexcel',
    cards: [
      { id: 'ep2-1', front: 'Comparison Connectives', back: 'Words and phrases used to link similarities and differences between texts.\n\nSimilarity: Similarly, Likewise, In the same way, Both writers, Equally.\nDifference: However, In contrast, Whereas, On the other hand, Conversely, Unlike.\n\nTip: Embed connectives naturally. Start with one text, then use a connective to pivot to the other.' },
      { id: 'ep2-2', front: 'Comparison Structures', back: 'Methods for organising a comparison essay.\n\nAlternating (preferred): Point about Text A > Compare to Text B > Repeat. Keeps comparison tight.\nBlock: All of Text A, then all of Text B. Risks losing comparison.\n\nBest practice: Each paragraph should discuss BOTH texts. Use "Similarly/However" to pivot between them.' },
      { id: 'ep2-3', front: 'AO3 — Comparison (Edexcel)', back: 'Compare writers\' ideas and perspectives, as well as how these are conveyed, across two or more texts.\n\nWhat this means: Compare WHAT the writers think (ideas/attitudes) and HOW they express it (methods/techniques).\n\nKey skill: Every analytical point must reference both texts. Use comparative connectives throughout.' },
      { id: 'ep2-4', front: 'Imaginative Writing', back: 'Creative writing that may be narrative (story) or descriptive.\n\nKey skills: Varied sentence structures, ambitious vocabulary, sensory imagery, structural techniques (flashback, zoom in/out, circular structure).\n\nEdexcel tip: You may be given an image or scenario as a stimulus. You can adapt it — you don\'t have to follow it literally.' },
      { id: 'ep2-5', front: 'Literary Non-Fiction', back: 'Real-life writing that uses literary techniques. Includes travel writing, autobiography, memoir, diary entries, journalism, letters.\n\nFeatures: Based on real events but uses techniques like imagery, dialogue, structural choices, and voice to engage readers.\n\nExam skill: Analyse it the same way you would fiction — look for language, structure, and writer\'s perspective.' },
      { id: 'ep2-6', front: 'Unreliable Narrator', back: 'A narrator whose account the reader cannot fully trust.\n\nSignals: Contradictions, bias, defensiveness, gaps in knowledge, emotional extremes, second-person justification ("You would have done the same").\n\nEffect: Creates suspense, forces reader to question events, adds psychological depth.\n\nUse in creative writing to add sophistication.' },
      { id: 'ep2-7', front: 'In Medias Res', back: 'Latin for "in the middle of things." Starting a narrative at a dramatic moment rather than the beginning.\n\nExample: Opening with action, dialogue, or a crisis, then filling in context later.\n\nEffect: Immediately hooks the reader. Creates intrigue and pace.\n\nUse in imaginative writing to grab the examiner\'s attention from line one.' },
      { id: 'ep2-8', front: 'Flashback', back: 'A shift to an earlier time in the narrative.\n\nTriggers: A sensory detail (smell, sound), an object, a place, a word.\n\nEffect: Adds backstory, reveals motivation, creates contrast between past and present.\n\nExam tip: In creative writing, use a single well-placed flashback rather than multiple time shifts.' },
      { id: 'ep2-9', front: 'Foreshadowing', back: 'Hints or clues about events that will happen later in the narrative.\n\nMethods: Symbolic imagery, ominous language, weather/atmosphere, a character\'s uneasy feeling.\n\nEffect: Builds tension, creates dramatic irony, rewards attentive readers.\n\nExam tip: Subtle foreshadowing shows skill — don\'t make it too obvious.' },
      { id: 'ep2-10', front: 'Narrative Voice', back: 'The perspective and personality through which a story is told.\n\nFirst person: "I" — intimate, subjective, potentially unreliable.\nThird person limited: Follows one character\'s thoughts.\nThird person omniscient: All-knowing narrator.\nSecond person: "You" — unusual, immersive, confrontational.\n\nChoose deliberately in creative writing and justify your choice through execution.' },
      { id: 'ep2-11', front: 'Zooming In (Structural Technique)', back: 'Moving from a wide, general view to a close, specific detail.\n\nExample: "The city sprawled beneath a grey sky... In one narrow alley, a single flower pushed through a crack in the concrete."\n\nEffect: Draws the reader\'s focus, creates significance from small details, mirrors a camera lens.\n\nUse in descriptive writing to control the reader\'s attention.' },
      { id: 'ep2-12', front: 'Circular / Cyclical Structure', back: 'When a text ends where it began — returning to the same image, place, or idea.\n\nEffect: Creates a sense of completion, inevitability, or entrapment. Can show that nothing has changed — or that everything has.\n\nExam tip: In creative writing, echo your opening in your final paragraph to demonstrate conscious structural control.' },
      { id: 'ep2-13', front: 'Shift in Tone', back: 'A deliberate change in the mood or attitude within a text.\n\nExamples: Humorous to serious, calm to panicked, hopeful to despairing.\n\nEffect: Creates contrast, surprise, or emotional impact. Shows the writer\'s control.\n\nExam tip: When analysing structure, always comment on WHERE and WHY the tone shifts.' },
      { id: 'ep2-14', front: 'Pathetic Fallacy (in Creative Writing)', back: 'Using weather, landscape, or environment to mirror a character\'s emotions or the mood of a scene.\n\nExample: "Rain hammered the windows as she stared at the letter" = grief, turmoil.\n\nExam tip: Use pathetic fallacy at the START of your creative writing to establish atmosphere immediately. Avoid cliches — be specific with weather details.' },
      { id: 'ep2-15', front: 'Sensory Imagery (Five Senses)', back: 'Language that appeals to sight, sound, touch, taste, and smell.\n\nVisual: "The crimson sun bled across the horizon."\nAuditory: "Silence pressed against his ears."\nTactile: "The rough bark scraped her palms."\nOlfactory: "The air was thick with woodsmoke."\nGustatory: "Salt stung his cracked lips."\n\nExam tip: Use at least THREE senses in any descriptive piece.' },
      { id: 'ep2-16', front: 'Show, Don\'t Tell', back: 'Revealing emotion through action, dialogue, and imagery rather than stating it directly.\n\nTelling: "She was nervous."\nShowing: "Her fingers drummed the tabletop. She glanced at the door, then back at her phone."\n\nEffect: More immersive and sophisticated. Trusts the reader to interpret.\n\nThis is the single most important technique for high-mark creative writing.' },
      { id: 'ep2-17', front: 'Perspective and Attitude', back: 'The writer\'s viewpoint on a topic and the feelings/opinions they convey.\n\nPerspective: Their angle or standpoint (e.g., a soldier\'s perspective on war vs a civilian\'s).\nAttitude: Their feelings — critical, admiring, nostalgic, ironic, angry.\n\nExam skill: In comparison questions, always compare perspectives AND how they are conveyed through methods.' },
      { id: 'ep2-18', front: 'Rhetorical Techniques (for Transactional Writing)', back: 'Persuasive methods for non-fiction writing:\n\nDARFOREST: Direct address, Alliteration, Rhetorical question, Facts, Opinions, Repetition, Emotive language, Statistics, Tricolon.\n\nExam tip: Don\'t just include these — use them purposefully. Quality over quantity. A well-placed rhetorical question is better than five crammed techniques.' },
      { id: 'ep2-19', front: 'Dialogue in Creative Writing', back: 'Speech between characters used to reveal personality, advance plot, or create tension.\n\nRules: New speaker = new line. Punctuation inside speech marks. Use speech verbs sparingly ("said" is fine).\n\nTips: Keep it brief and purposeful. What characters DON\'T say can be as powerful as what they do. Subtext (saying one thing, meaning another) shows sophistication.' },
      { id: 'ep2-20', front: 'Ambitious Vocabulary', back: 'Precise, carefully chosen words that elevate your writing beyond the everyday.\n\nNot: "The old house was scary."\nBetter: "The decrepit house loomed, its hollow windows like vacant eyes."\n\nKey principle: Choose words for PRECISION, not complexity. "Trudged" is better than "walked laboriously" because it is vivid and concise.\n\nExam tip: 5-10 well-chosen ambitious words across a piece is enough. Overdoing it sounds forced.' },
    ],
  },
  {
    id: 'edexcel-1en2-paper-1-key-terms',
    title: 'Edexcel Paper 1: Advanced Terminology',
    description: 'Terminology specific to 19th-century non-fiction reading and transactional writing for Edexcel 1EN2 Paper 1',
    category: 'gcse',
    board: 'Edexcel',
    cards: [
      { id: 'e1kt-1', front: 'Rhetoric', back: 'The art of effective or persuasive speaking and writing. In Edexcel Paper 1, 19th-century non-fiction sources are rich in rhetorical strategies.\n\nKey rhetorical devices: tricolon, anaphora, antithesis, rhetorical questions, direct address.\n\nWhen analysing the source in Section A, identify the writer\'s rhetorical purpose — are they arguing, persuading, informing, or entertaining? This shapes every language choice they make.' },
      { id: 'e1kt-2', front: 'Polemic', back: 'A strong, one-sided verbal attack against an opposing position or belief.\n\n19th-century writers frequently used polemic to campaign for social reform. Examples: Dickens on workhouses, Wollstonecraft on women\'s education.\n\nFeatures: passionate tone, emotive language, exaggeration, direct appeals to morality.\n\nUse in Q3/Q4 analysis: "The text functions as a polemic against [X], as evidenced by..."' },
      { id: 'e1kt-3', front: 'Epistolary', back: 'Relating to or in the form of letters. An epistolary text is written as correspondence.\n\nEdexcel Paper 1 may use a 19th-century published letter as the source text.\n\nConventions: salutation ("Dear Sir"), personal address, intimate or public tone, sign-off.\n\nAnalysis tip: Consider who the letter is addressed to and how the audience shapes the writer\'s tone, register, and rhetorical choices.' },
      { id: 'e1kt-4', front: 'Didactic', back: 'Writing intended to teach, instruct, or moralise.\n\nMuch 19th-century non-fiction is didactic — aimed at educating the public about social issues, moral conduct, or civic duty.\n\nExamples: pamphlets on temperance, essays on child labour, sermons on charity.\n\nIn your analysis, consider: What lesson does the writer want the reader to learn? How do their methods serve this didactic purpose?' },
      { id: 'e1kt-5', front: 'Invective', back: 'Vehement, abusive, or highly critical language directed against a person, group, or idea.\n\n19th-century journalists and commentators used invective to discredit opponents and provoke outrage.\n\nEffect: vilifies the target, stirs anger in the reader, positions the writer as morally superior.\n\nIn Q3: "The writer employs invective through [specific language choices], creating a tone of righteous condemnation."' },
      { id: 'e1kt-6', front: 'Tract / Pamphlet', back: 'Short printed publications on a single issue, widely distributed in the 19th century for political or social campaigning.\n\nTracts were often religious or moral; pamphlets were broader (political, social, satirical).\n\nFeatures: urgent tone, clear thesis, persuasive techniques, call to action.\n\nMay appear as a Paper 1 source. Analyse the writer\'s methods of persuasion and their intended effect on the original audience.' },
      { id: 'e1kt-7', front: 'Oratory / Oration', back: 'The art of public speaking, or a formal speech. Many 19th-century non-fiction texts were originally delivered as speeches.\n\nOratorical features: direct address, repetition, anaphora, rhetorical questions, tricolon, pauses for effect.\n\nWhen analysing a speech extract in Paper 1, consider how it would SOUND — rhythm, emphasis, and pacing matter as much as word choice.' },
      { id: 'e1kt-8', front: 'Philanthropic Discourse', back: 'Language relating to charitable concern for human welfare. Common in 19th-century reform writing.\n\nKey vocabulary: benevolence, compassion, duty, moral obligation, the deserving poor.\n\nWriters used philanthropic discourse to appeal to wealthy readers\' sense of duty.\n\nContrast with: Malthusian discourse (the poor as "surplus population") — identifying which discourse a writer uses shows sophisticated contextual understanding.' },
      { id: 'e1kt-9', front: 'Satirical Tone', back: 'The use of irony, exaggeration, or ridicule to criticise and mock individuals, institutions, or society.\n\n19th-century writers like Dickens, Wilde, and Swift (earlier) used satire to expose hypocrisy.\n\nKey signals: verbal irony, understatement, mock-serious tone, absurd comparisons.\n\nIn Q3: Explain HOW the satirical tone works — what is being mocked, and how does irony achieve this more effectively than direct criticism?' },
      { id: 'e1kt-10', front: 'Encomium', back: 'A formal expression of praise, often in speech or essay form.\n\nThe opposite of invective. Some 19th-century texts praise individuals, institutions, or ideals to inspire admiration and emulation.\n\nFeatures: superlative adjectives, elevated diction, tricolon, idealised imagery.\n\nUseful for Q4 comparison: "While Source A uses invective to condemn [X], Source B employs encomium to celebrate [Y]."' },
      { id: 'e1kt-11', front: 'Apostrophe (Rhetorical)', back: 'NOT the punctuation mark. A rhetorical device where the speaker directly addresses an absent person, abstract concept, or object.\n\nExample: "O Liberty! How many crimes are committed in thy name!"\n\nCommon in 19th-century speeches and essays. Effect: creates emotional intensity and dramatic flair.\n\nDo not confuse with the punctuation term — context makes the meaning clear.' },
      { id: 'e1kt-12', front: 'Synthesis (Paper 1 Q2)', back: 'The skill of drawing together information from TWO sources to identify similarities or differences.\n\nEdexcel Paper 1 Q2 (8 marks) requires synthesis, not just summary.\n\nTechnique: Make a comparative point → support with evidence from Source A → link to Source B with a connective.\n\nKey connectives: "Similarly," "Both sources suggest," "In contrast," "Whereas Source A..., Source B..."' },
      { id: 'e1kt-13', front: 'Concession and Rebuttal', back: 'Concession: Acknowledging an opposing argument has some validity.\nRebuttal: Then countering it with a stronger point.\n\nStructure: "While it may be true that [concession], it is nevertheless the case that [rebuttal]."\n\nCommon in 19th-century argument and essential for your own Section B transactional writing. Shows sophistication and earns top-band marks.' },
      { id: 'e1kt-14', front: 'Peroration', back: 'The concluding section of a speech or argument, designed to be powerful and memorable.\n\nFeatures: emotional climax, call to action, tricolon, repetition, heightened language.\n\nIn 19th-century speeches, the peroration was often the most passionate section.\n\nFor Q4: Comparing how two writers END their texts (their perorations) is a sophisticated structural point.' },
      { id: 'e1kt-15', front: 'Register and Audience', back: 'Register = the level of formality determined by audience and purpose.\n\nFormal: complex sentences, Latinate vocabulary, impersonal constructions.\nInformal: contractions, colloquialisms, first person, shorter sentences.\n\n19th-century texts typically use formal register. For Section B, you MUST match register to your specified audience — a letter to an MP requires different register than a blog post.' },
      { id: 'e1kt-16', front: 'Diatribe', back: 'A forceful, bitter, sustained verbal attack or denunciation.\n\nStronger than criticism, more sustained than invective. A diatribe is an extended rant against a target.\n\nCommon in 19th-century political journalism and reform writing.\n\nEffect: overwhelms the reader with the force of the writer\'s anger; leaves no room for counterargument.\n\nUseful analytical term for Q3 when the source text is particularly aggressive.' },
      { id: 'e1kt-17', front: 'Exordium', back: 'The opening section of a speech or argument, designed to capture attention and establish credibility.\n\nFeatures: hook, establishment of the writer\'s authority, statement of purpose.\n\nFor Q3/Q4 structural analysis: "The writer\'s exordium immediately establishes [authority/urgency/sympathy] through [specific technique]."\n\nCompare how two writers open their texts for a strong Q4 structural comparison.' },
    ],
  },
  {
    id: 'edexcel-1en2-paper-2-key-terms',
    title: 'Edexcel Paper 2: Advanced Terminology',
    description: 'Terminology for fiction analysis and imaginative writing for Edexcel 1EN2 Paper 2',
    category: 'gcse',
    board: 'Edexcel',
    cards: [
      { id: 'e2kt-1', front: 'Narrative Voice', back: 'The perspective and personality through which a story is told. Central to Paper 2 fiction analysis.\n\nFirst person ("I"): subjective, intimate, potentially unreliable.\nThird person limited: follows one character\'s thoughts.\nThird person omniscient: all-knowing, can reveal any character\'s mind.\nSecond person ("you"): unusual, immersive, confrontational.\n\nAlways comment on narrative voice in Q3 — it shapes everything the reader experiences.' },
      { id: 'e2kt-2', front: 'Foreshadowing', back: 'Hints or clues planted early in a narrative that anticipate later events.\n\nMethods: ominous imagery, loaded dialogue, symbolic objects, weather/atmosphere.\n\nExample: A character noticing a cracked mirror before a relationship breaks down.\n\nIn Paper 2 Q3: "The writer foreshadows [event] through [specific detail], creating a sense of unease that prepares the reader for..."' },
      { id: 'e2kt-3', front: 'Pathetic Fallacy', back: 'Attributing human emotions to the natural environment, especially weather, to mirror characters\' feelings or establish mood.\n\nExample: "The sky darkened and rain began to spit as he turned away."\n\nDistinct from personification — pathetic fallacy specifically reflects EMOTION through ENVIRONMENT.\n\nEssential for both fiction analysis (Q3) and your own imaginative writing (Q5).' },
      { id: 'e2kt-4', front: 'Motif', back: 'A recurring image, symbol, idea, or phrase that develops significance across a text.\n\nExample: Repeated references to clocks in a text about mortality.\n\nEven in a short Paper 2 extract, a motif may appear multiple times. Spotting it shows perceptive reading.\n\nIn your imaginative writing: Introduce a motif early, repeat it with variation, and return to it at the end for structural cohesion.' },
      { id: 'e2kt-5', front: 'Denouement', back: 'The final resolution of a narrative, where conflicts are resolved and loose ends are tied up.\n\nFrom French: "unknotting."\n\nFollows the climax. May be satisfying (closure) or ambiguous (open ending).\n\nIf the Paper 2 extract is from near a story\'s end, consider whether the denouement resolves expectations or deliberately subverts them.' },
      { id: 'e2kt-6', front: 'Free Indirect Discourse', back: 'A narrative technique blending a character\'s thoughts with the narrator\'s voice, without speech marks or "she thought."\n\nExample: "She stared at the letter. It was over, then. Everything she had worked for, gone."\n\nThe second and third sentences are the character\'s thoughts, rendered in the narrator\'s voice.\n\nIdentifying this in Paper 2 Q3 shows very sophisticated understanding of narrative technique.' },
      { id: 'e2kt-7', front: 'In Medias Res', back: 'Latin: "in the middle of things." Beginning a narrative at a dramatic or significant moment rather than at the chronological start.\n\nEffect: Immediately hooks the reader. Creates mystery about how events reached this point.\n\nUse in your Paper 2 Q5 imaginative writing: open with a moment of tension or significance, then fill in context through flashback or reflection.' },
      { id: 'e2kt-8', front: 'Dramatic Irony', back: 'When the reader knows something that a character does not.\n\nExample: The reader knows there is danger ahead, but the character walks on obliviously.\n\nEffect: Creates tension, suspense, or pathos. The reader becomes emotionally invested because they want to warn the character.\n\nIn fiction analysis, always explain the EFFECT of dramatic irony on the reader\'s experience.' },
      { id: 'e2kt-9', front: 'Semantic Field', back: 'A group of words in a text that all relate to the same topic or concept.\n\nExample: "shackled," "imprisoned," "confined," "locked" = semantic field of captivity.\n\nIn Paper 2 Q3: Identifying a semantic field shows you can see patterns across the extract, not just individual words. Explain what the sustained semantic field SUGGESTS about theme or character.' },
      { id: 'e2kt-10', front: 'Epiphany', back: 'A sudden moment of revelation or insight experienced by a character.\n\nOften occurs at or near the climax. The character suddenly understands something they previously could not see.\n\nEffect: Creates a turning point. Can be cathartic, devastating, or transformative.\n\nIn fiction analysis: "The protagonist experiences an epiphany when [event], realising that [insight]."' },
      { id: 'e2kt-11', front: 'Exposition', back: 'The opening section of a narrative where the writer establishes setting, characters, context, and initial situation.\n\nIn Paper 2 fiction extracts, the exposition sets tone and atmosphere.\n\nFor your own imaginative writing: Keep exposition brief. Start with action, dialogue, or a striking image. Weave context in gradually — do not dump information in the first paragraph.' },
      { id: 'e2kt-12', front: 'Prolepsis', back: 'A flash-forward — a scene or detail that jumps ahead in time to reveal or hint at future events.\n\nOpposite of analepsis (flashback).\n\nExample: "Years later, she would remember this moment as the one that changed everything."\n\nEffect: Creates anticipation and a sense of inevitability. Sophisticated structural technique for Q5 imaginative writing.' },
      { id: 'e2kt-13', front: 'Unreliable Narrator', back: 'A narrator whose account the reader cannot fully trust due to bias, limited knowledge, emotional distortion, or deliberate deception.\n\nSignals: contradictions, defensiveness, gaps, excessive justification, second-person address ("You would have done the same").\n\nIdentifying unreliable narration in Paper 2 Q3 is a top-band skill. Using one in Q5 shows creative sophistication.' },
      { id: 'e2kt-14', front: 'Sensory Description', back: 'Writing that appeals to the five senses: sight, sound, touch, taste, smell.\n\nMost students only use sight. To reach top bands in Paper 2 Q5, consciously include at least three senses.\n\nTactile: "The rough bark scraped her palms."\nOlfactory: "Damp earth and woodsmoke hung in the air."\nAuditory: "Silence pressed in from every side."\n\nSensory detail creates immersion — the examiner should FEEL your writing.' },
      { id: 'e2kt-15', front: 'Cyclical / Circular Structure', back: 'A narrative that ends where it began, returning to the opening image, location, or idea.\n\nEffect: Creates a sense of completion, fate, or entrapment. Can show transformation (same place, changed character) or stasis (nothing has changed).\n\nIn Paper 2 Q5: Echo your opening line or image in your final paragraph. This single structural choice demonstrates conscious craft and earns AO5 marks.' },
      { id: 'e2kt-16', front: 'Narrative Pace', back: 'The speed at which events unfold in a story, controlled by the writer\'s structural and linguistic choices.\n\nFast pace: short sentences, dialogue, action verbs, minimal description.\nSlow pace: long sentences, sensory detail, extended imagery, reflection.\n\nIn Q3 analysis: comment on how pace shifts create tension or emphasis.\nIn Q5 writing: vary pace deliberately — slow description followed by sudden short sentences creates impact.' },
      { id: 'e2kt-17', front: 'Atmosphere vs. Mood', back: 'Often used interchangeably, but there is a useful distinction:\n\nAtmosphere: the feeling created by the SETTING and ENVIRONMENT (external).\nMood: the emotional state of the CHARACTER or READER (internal).\n\nIn Paper 2 analysis, use precise terms: "The writer creates a claustrophobic atmosphere through [detail], which evokes a mood of anxiety in the reader."\n\nPrecise vocabulary like this signals top-band analysis.' },
    ],
  },
  {
    id: 'edexcel-1en2-assessment-objectives',
    title: 'Edexcel Assessment Objectives',
    description: 'AO1 through AO6 for Edexcel 1EN2 English Language with specific mark allocations and examiner expectations',
    category: 'gcse',
    board: 'Edexcel',
    cards: [
      { id: 'eao2-1', front: 'AO1 — Identify and Interpret', back: 'Identify and interpret explicit and implicit information and ideas. Select and synthesise evidence from different texts.\n\nEdexcel 1EN2 application:\n• Paper 1 Q1 (4 marks): Retrieve explicit information from one source.\n• Paper 1 Q2 (8 marks): Synthesise information from BOTH sources.\n• Paper 2 Q1 (4 marks): Retrieve information from the fiction extract.\n• Paper 2 Q2 (8 marks): Summarise/synthesise from one or two texts.\n\nKey skill: Inference — reading between the lines, not just surface comprehension.' },
      { id: 'eao2-2', front: 'AO2 — Analyse Language and Structure', back: 'Explain, comment on and analyse how writers use language and structure to achieve effects and influence readers, using relevant subject terminology.\n\nEdexcel 1EN2 application:\n• Paper 1 Q3 (12 marks): Language analysis of one non-fiction source.\n• Paper 1 Q4 (16 marks): Compare writers\' methods across both sources.\n• Paper 2 Q3 (12 marks): Language AND structure analysis of fiction.\n• Paper 2 Q4 (16 marks): Evaluate the writer\'s methods.\n\nThis is the highest-weighted reading AO. Always analyse EFFECT — do not just spot techniques.' },
      { id: 'eao2-3', front: 'AO3 — Compare Writers\' Ideas and Perspectives', back: 'Compare writers\' ideas and perspectives, as well as how these are conveyed, across two or more texts.\n\nEdexcel 1EN2 application:\n• Tested in Paper 1 Q4 (16 marks) — comparing two non-fiction sources.\n\nYou must compare BOTH ideas (what they think) AND methods (how they express it).\n\nStructure each paragraph around a comparative point. Use connectives: "Similarly," "Whereas," "Both writers," "In contrast."\n\nDo NOT write about each text separately — integrate comparison throughout.' },
      { id: 'eao2-4', front: 'AO4 — Evaluate Critically', back: 'Evaluate texts critically and support this with appropriate textual references.\n\nEdexcel 1EN2 application:\n• Tested in Paper 2 Q4 (16 marks).\n• You are given a statement about the text and asked how far you agree.\n\nYou must JUDGE effectiveness, not just describe.\n\nKey phrases: "The writer effectively...", "This is convincing because...", "A less successful aspect is..."\n\nSustained evaluation throughout = top band. A single evaluative sentence is not enough.' },
      { id: 'eao2-5', front: 'AO5 — Communicate and Organise (Writing)', back: 'Communicate clearly, effectively and imaginatively, selecting and adapting tone, style and register for different forms, purposes and audiences. Organise information and ideas, using structural and grammatical features to support coherence and cohesion.\n\nEdexcel 1EN2 application:\n• Paper 1 Q5: 24 marks (transactional writing).\n• Paper 2 Q5: 24 marks (imaginative writing).\n\nCovers: quality of ideas, audience awareness, register, paragraphing, structural devices, coherence.\n\nThis is the LARGEST single mark allocation on both papers.' },
      { id: 'eao2-6', front: 'AO6 — Technical Accuracy (Writing)', back: 'Use a range of vocabulary and sentence structures for clarity, purpose and effect, with accurate spelling and punctuation.\n\nEdexcel 1EN2 application:\n• Paper 1 Q5: 16 marks.\n• Paper 2 Q5: 16 marks.\n\nCovers: spelling accuracy, punctuation variety (semicolons, colons, dashes, ellipsis), sentence variety (simple, compound, complex, minor), ambitious vocabulary.\n\nThese are the most accessible marks on the paper. Accuracy costs nothing but time — proofread your final 5 minutes.' },
      { id: 'eao2-7', front: 'Paper 1 Full Mark Breakdown (1EN2/01)', back: 'Total: 80 marks | 1 hour 45 minutes\n\nSection A — Reading (40 marks):\n• Q1: 4 marks (AO1) — information retrieval from one source\n• Q2: 8 marks (AO1) — synthesis across both sources\n• Q3: 12 marks (AO2) — language analysis of one source\n• Q4: 16 marks (AO2 + AO3) — compare writers\' methods\n\nSection B — Transactional Writing (40 marks):\n• Q5: 24 marks (AO5) + 16 marks (AO6) = 40 marks\n\nReading and writing are equally weighted at 50% each.' },
      { id: 'eao2-8', front: 'Paper 2 Full Mark Breakdown (1EN2/02)', back: 'Total: 80 marks | 2 hours 5 minutes\n\nSection A — Reading (40 marks):\n• Q1: 4 marks (AO1) — information retrieval from fiction extract\n• Q2: 8 marks (AO1) — summary or synthesis\n• Q3: 12 marks (AO2) — language and structure analysis\n• Q4: 16 marks (AO2 + AO4) — critical evaluation\n\nSection B — Imaginative Writing (40 marks):\n• Q5: 24 marks (AO5) + 16 marks (AO6) = 40 marks\n\nPaper 2 has 20 extra minutes — use them for the longer fiction extract and creative writing planning.' },
      { id: 'eao2-9', front: 'How AOs Map to Grade Boundaries', back: 'Grade 8–9: Perceptive, detailed AO2 analysis with judicious evidence. Compelling, crafted writing (AO5) with assured technical accuracy (AO6).\n\nGrade 6–7: Convincing AO2 analysis with well-chosen evidence. Engaging, well-structured writing with consistent accuracy.\n\nGrade 4–5: Clear AO2 analysis with relevant evidence. Coherent writing with generally accurate spelling and punctuation.\n\nGrade 1–3: Simple or tentative responses. Basic writing with frequent errors.\n\nWriting (AO5 + AO6) is 50% of each paper — a strong writer can compensate for weaker reading skills.' },
      { id: 'eao2-10', front: 'The Difference Between AO2 and AO4', back: 'AO2 = ANALYSE how the writer uses language and structure.\nAO4 = EVALUATE how effectively the writer achieves their purpose.\n\nAO2 asks: "What techniques does the writer use and what effects do they create?"\nAO4 asks: "How well does this work? Is it effective or not?"\n\nAO2 is tested on BOTH papers (Q3 and Q4 on Paper 1; Q3 on Paper 2).\nAO4 is ONLY tested on Paper 2 Q4.\n\nFor AO4, you must make value judgements: "This is effective because..." or "This is less convincing because..."' },
    ],
  },
  {
    id: 'edexcel-1en2-mark-scheme-vocabulary',
    title: 'Edexcel Mark Scheme Vocabulary',
    description: 'Key descriptors from Edexcel 1EN2 mark schemes and the grade boundaries they correspond to',
    category: 'gcse',
    board: 'Edexcel',
    cards: [
      { id: 'emsv2-1', front: 'Perceptive', back: 'Grade 8–9 (Band 5) reading descriptor.\n\nMeaning: Showing deep, insightful understanding that goes beyond the obvious. The student notices what other readers miss.\n\nHow to achieve it:\n• Make original interpretations — do not repeat obvious points.\n• Explore multiple layers of meaning in a single quote.\n• Consider what the writer implies or leaves unsaid.\n• Connect techniques to the writer\'s broader purpose.\n\nA "perceptive" response makes the examiner think: "I hadn\'t considered that."' },
      { id: 'emsv2-2', front: 'Judicious', back: 'Grade 8–9 (Band 5) descriptor for evidence use.\n\nMeaning: Showing excellent judgement in selecting quotations. Every piece of evidence is precisely chosen and perfectly supports the point.\n\nHow to achieve it:\n• Use SHORT embedded quotations (2–5 words).\n• Zoom into individual words within the quote.\n• Never quote an entire sentence when a phrase will do.\n• Every quote must earn its place — if it does not directly support your point, cut it.\n\n"Judicious" = surgical precision, not volume.' },
      { id: 'emsv2-3', front: 'Compelling', back: 'Grade 8–9 (Band 5) writing descriptor (AO5).\n\nMeaning: Writing so convincing, powerful, and engaging that the reader cannot stop reading.\n\nHow to achieve it:\n• Hook the reader from the first sentence.\n• Maintain a confident, controlled tone throughout.\n• Structure deliberately — every paragraph has purpose.\n• End memorably — the conclusion should resonate.\n\n"Compelling" writing makes the examiner forget they are marking.' },
      { id: 'emsv2-4', front: 'Assured', back: 'Grade 7–9 (Band 4–5) writing descriptor.\n\nMeaning: Confident and controlled. The writer knows exactly what they are doing and never loses grip.\n\nHow to achieve it:\n• Consistent register — do not accidentally slip between formal and informal.\n• Deliberate technique choices — every device serves a purpose.\n• No awkward phrasing or clumsy sentences.\n• Smooth transitions between paragraphs.\n\n"Assured" = the opposite of hesitant. Write with authority.' },
      { id: 'emsv2-5', front: 'Convincing', back: 'Grade 7 (Band 4) descriptor for both reading and writing.\n\nMeaning: The response is believable, well-supported, and holds together logically.\n\nFor reading: Your analysis is well-evidenced and your interpretations are plausible.\nFor writing: Your argument is logical (transactional) or your narrative feels authentic (imaginative).\n\nThe gap between "convincing" and "compelling": Convincing = you believe it. Compelling = you cannot look away.' },
      { id: 'emsv2-6', front: 'Credible', back: 'Grade 5–6 (Band 3) descriptor.\n\nMeaning: The response is reasonable, makes sense, and shows understanding, but lacks the depth or flair of higher bands.\n\nFor reading: Points are valid but not deeply developed.\nFor writing: The piece communicates clearly but does not excite.\n\nTo move beyond "credible": Add a second layer of analysis. Do not just explain what a technique does — explore WHY the writer chose it and what alternatives they rejected.' },
      { id: 'emsv2-7', front: 'Clear', back: 'Grade 4–5 (Band 3) descriptor.\n\nMeaning: The response communicates ideas that can be understood and followed.\n\nThis is the baseline for a secure pass. "Clear" = the examiner can follow your argument without confusion.\n\nLimitations of "clear": It implies competence but not sophistication. There is no deeper insight, no originality, no flair.\n\nTo upgrade: Add analysis of individual words, explore alternative interpretations, use precise vocabulary.' },
      { id: 'emsv2-8', front: 'Sustained', back: 'Appears across multiple bands. Means the quality is maintained consistently from beginning to end.\n\nA "sustained" argument does not lose focus after two paragraphs.\nA "sustained" narrative does not lose control of tone halfway through.\n"Sustained" accuracy means few errors throughout, not just at the start.\n\nCommon mistake: Students write a strong opening then lose quality as they rush. Plan your time so the final paragraphs are as strong as the first.' },
      { id: 'emsv2-9', front: 'Apt', back: 'Grade 7–9 (Band 4–5) descriptor for subject terminology and evidence.\n\nMeaning: Appropriate, fitting, precisely right for the context.\n\n"Apt terminology" = using exactly the right technical term at the right moment (not forcing in terms that do not fit).\n"Apt references" = choosing evidence that precisely supports your specific point.\n\nThe opposite of "apt" is "forced" — do not name a technique just to show you know it. Only use terminology that genuinely aids your analysis.' },
      { id: 'emsv2-10', front: 'Discerning', back: 'Grade 8–9 (Band 5) descriptor.\n\nMeaning: Showing the ability to judge quality and distinguish subtle differences.\n\nA "discerning" reader notices that a writer\'s tone shifts from resigned to defiant — not just that "the writer is emotional."\n\nA "discerning" writer makes subtle choices: the difference between "said" and "murmured," between a full stop and a dash.\n\nDiscernment = noticing and articulating what is fine-grained and nuanced.' },
      { id: 'emsv2-11', front: 'Coherent', back: 'Grade 4–6 (Band 3) writing descriptor for organisation.\n\nMeaning: Ideas are logically connected and the text makes sense as a whole.\n\nHow to achieve it:\n• Use discourse markers (however, furthermore, consequently).\n• One clear topic per paragraph.\n• Link conclusion back to introduction.\n\nCoherent is necessary but not sufficient for top marks. A text can be coherent and dull. Aim for coherent AND compelling.' },
      { id: 'emsv2-12', front: 'Tentative', back: 'Grade 1–3 (Band 1–2) descriptor.\n\nMeaning: Uncertain, vague, undeveloped. The student gestures at an idea but does not commit to it or develop it.\n\nExample of tentative analysis: "The writer uses a metaphor which is effective."\n\nTo avoid being tentative:\n• Develop every point fully.\n• Use evidence to support every claim.\n• Explain effects specifically — "effective" is not analysis.\n• Commit to your interpretation — do not hedge with "maybe" or "might."' },
      { id: 'emsv2-13', front: 'Crafted', back: 'Grade 8–9 (Band 5) writing descriptor.\n\nMeaning: Writing that shows deliberate, skilled construction at every level — word choice, sentence structure, paragraphing, overall shape.\n\n"Crafted" writing reads as literary, not merely competent. The examiner senses that every choice was intentional.\n\nHow to achieve it: After writing, re-read and refine. Change a word for a better one. Split a long sentence for impact. Move a paragraph for better flow. This revision process IS craft.' },
      { id: 'emsv2-14', front: 'Integrated', back: 'Grade 7–9 (Band 4–5) descriptor, especially for comparison responses.\n\nMeaning: Ideas from different texts are woven together, not treated in separate blocks.\n\nFor Paper 1 Q4: Do NOT write all about Source A, then all about Source B. Each paragraph should discuss BOTH texts around a shared point.\n\nStructure: "Both writers [shared technique/idea]. Source A achieves this through [method], whereas Source B [contrasting method]."' },
      { id: 'emsv2-15', front: 'Band Progression Summary', back: 'Band 1 (Grade 1–2): Simple, tentative, limited.\nBand 2 (Grade 3): Attempts, some relevant comment.\nBand 3 (Grade 4–5): Clear, credible, coherent, relevant.\nBand 4 (Grade 6–7): Convincing, assured, well-chosen evidence.\nBand 5 (Grade 8–9): Perceptive, discerning, judicious, compelling, crafted.\n\nThe jump from Band 3 to Band 4 requires DEPTH of analysis.\nThe jump from Band 4 to Band 5 requires ORIGINALITY and PRECISION.' },
    ],
  },
  {
    id: 'edexcel-1en2-exam-technique',
    title: 'Edexcel Exam Technique',
    description: 'Question-specific strategies, timing, and mark allocations for every question on Edexcel 1EN2 Papers 1 and 2',
    category: 'gcse',
    board: 'Edexcel',
    cards: [
      { id: 'eet2-1', front: 'Paper 1 Timing Strategy (1 hour 45 mins)', back: 'Total: 105 minutes for 80 marks.\n\nRecommended split:\n• Read both sources: 10 minutes\n• Q1 (4 marks): 5 minutes\n• Q2 (8 marks): 10 minutes\n• Q3 (12 marks): 15 minutes\n• Q4 (16 marks): 20 minutes\n• Q5 (40 marks): 45 minutes (5 plan + 35 write + 5 check)\n\nGolden rule: 1 minute per mark. Never spend 20 minutes on a 4-mark question. Protect your Q5 time — it is worth HALF the paper.' },
      { id: 'eet2-2', front: 'Paper 2 Timing Strategy (2 hours 5 mins)', back: 'Total: 125 minutes for 80 marks.\n\nRecommended split:\n• Read the fiction extract: 10–15 minutes (it is longer than Paper 1 sources)\n• Q1 (4 marks): 5 minutes\n• Q2 (8 marks): 10 minutes\n• Q3 (12 marks): 15 minutes\n• Q4 (16 marks): 20 minutes\n• Q5 (40 marks): 55 minutes (5 plan + 45 write + 5 check)\n\nYou have 20 extra minutes compared to Paper 1. Use them for careful reading and extended creative writing.' },
      { id: 'eet2-3', front: 'Paper 1 Q1 — Information Retrieval (4 marks, AO1)', back: 'Task: Identify 4 pieces of information from ONE specified source.\n\nStrategy:\n• Read the question to find which source and which lines.\n• Give 4 short, distinct points — one per mark.\n• Use your own words or direct reference.\n• No analysis needed — this is pure comprehension.\n\nTiming: 5 minutes maximum.\nCommon mistake: Writing too much. Brief, accurate points are all that is needed.' },
      { id: 'eet2-4', front: 'Paper 1 Q2 — Synthesis (8 marks, AO1)', back: 'Task: Use BOTH sources to explain similarities or differences on a given topic.\n\nStrategy:\n• Make 3–4 developed comparative points.\n• Each point MUST reference both sources.\n• Infer — go beyond surface information.\n• Use connectives: "Similarly," "Both writers suggest," "In contrast."\n\nStructure per point: Inference from Source A → supporting evidence → link to Source B → supporting evidence → brief development.\n\nTiming: 10 minutes.' },
      { id: 'eet2-5', front: 'Paper 1 Q3 — Language Analysis (12 marks, AO2)', back: 'Task: Analyse how the writer uses language to [specific effect] in ONE source.\n\nStrategy:\n• Write 3–4 detailed PEAL paragraphs.\n• P = Point about effect. E = Embedded quote (short). A = Analyse technique and word choice. L = Link to reader\'s response.\n• Zoom into INDIVIDUAL WORDS — do not just quote a whole sentence.\n• Name techniques only when it aids analysis.\n\nTiming: 15 minutes.\nKey: Always explain EFFECT. "The writer uses alliteration" = 0 marks without explaining WHY it matters.' },
      { id: 'eet2-6', front: 'Paper 1 Q4 — Compare Writers\' Methods (16 marks, AO2 + AO3)', back: 'Task: Compare how both writers convey their perspectives on a given theme.\n\nStrategy:\n• 4–5 integrated comparative paragraphs.\n• Each paragraph: comparative topic sentence → Source A analysis → comparative connective → Source B analysis → evaluation of difference/similarity.\n• Compare METHODS (language, structure, tone) not just IDEAS.\n• Address both micro (word choice) and macro (structure, form, purpose).\n\nTiming: 20 minutes.\nThis is the highest-mark reading question. Give it the attention it deserves.' },
      { id: 'eet2-7', front: 'Paper 1 Q5 — Transactional Writing (40 marks, AO5 + AO6)', back: 'Task: Write in a specified form (letter, article, speech, review, blog, report, guide, email) to argue, persuade, advise, or inform.\n\nStrategy:\n1. PLAN (5 mins): Purpose, audience, form, 4–5 key points, opening hook, closing statement.\n2. WRITE (35 mins): Match register to audience. Use rhetorical devices purposefully. Paragraph clearly. Vary sentences.\n3. CHECK (5 mins): Spelling, punctuation, sentence clarity.\n\nForm conventions matter: A speech needs direct address and rhetorical flourish. A letter needs addresses and sign-off. An article needs a headline.\n\n24 marks for content/organisation + 16 marks for accuracy = your biggest single mark allocation.' },
      { id: 'eet2-8', front: 'Paper 2 Q1 — Information Retrieval (4 marks, AO1)', back: 'Task: Identify 4 pieces of information from the fiction extract.\n\nStrategy:\n• Read the question to find which section of the extract.\n• Give 4 short, distinct points.\n• These can be one sentence each.\n• No analysis — just accurate comprehension.\n\nTiming: 5 minutes maximum.\nTip: This is the easiest question on the paper. Get 4/4 and move on quickly.' },
      { id: 'eet2-9', front: 'Paper 2 Q2 — Summary/Synthesis (8 marks, AO1)', back: 'Task: Summarise key aspects from the text(s) on a specific topic.\n\nStrategy:\n• Make 3–4 clear points with evidence.\n• Infer beyond the literal — what is implied?\n• Keep quotes short and embedded.\n• If comparing two texts, use comparative connectives.\n\nTiming: 10 minutes.\nKey difference from Q1: Q2 requires INFERENCE and DEVELOPMENT, not just retrieval. A point without development earns half marks.' },
      { id: 'eet2-10', front: 'Paper 2 Q3 — Language and Structure Analysis (12 marks, AO2)', back: 'Task: Analyse how the writer uses language AND structure to create effects in the fiction extract.\n\nStrategy:\n• Cover BOTH language and structure — ignoring either caps your mark.\n• Language: word choice, imagery, figurative language, tone, dialogue.\n• Structure: opening, shifts in focus/pace/tone, narrative perspective, paragraph length, ending.\n• Write 3–4 detailed paragraphs with embedded quotations.\n\nTiming: 15 minutes.\nTop tip: One paragraph on structure minimum. Comment on WHERE in the extract something happens and WHY the writer places it there.' },
      { id: 'eet2-11', front: 'Paper 2 Q4 — Critical Evaluation (16 marks, AO2 + AO4)', back: 'Task: Evaluate how effectively the writer achieves a specific effect. You are given a statement and asked how far you agree.\n\nStrategy:\n• Write 4–5 paragraphs.\n• Each paragraph: state your evaluative judgement → provide evidence → analyse how the technique creates the effect → evaluate its success.\n• Use evaluative language throughout: "effectively," "convincingly," "powerfully," "less successfully."\n• You CAN partially disagree — nuance shows critical thinking.\n\nTiming: 20 minutes.\nCritical: This is NOT just analysis. You must JUDGE effectiveness. Every paragraph needs an evaluative statement.' },
      { id: 'eet2-12', front: 'Paper 2 Q5 — Imaginative Writing (40 marks, AO5 + AO6)', back: 'Task: Write a narrative or descriptive piece, often linked to an image or theme prompt.\n\nStrategy:\n1. PLAN (5 mins): Character, setting, conflict, 5-part structure (opening → build → shift → climax → resolution), ending.\n2. WRITE (45 mins): Choose a SMALL moment. Write it in DEPTH. Show, don\'t tell. Use sensory detail (3+ senses). Vary sentences. Use a structural device (cyclical, flashback, zoom in/out).\n3. CHECK (5 mins): Spelling, punctuation, sentence boundaries.\n\nGolden rule: A vivid, controlled 1.5 pages beats a rushed, sprawling 3 pages. Quality over quantity.' },
      { id: 'eet2-13', front: 'How to Embed Quotations Effectively', back: 'Embedding = weaving quotes into your own sentences so they read grammatically.\n\nWeak: The writer says "the bitter wind howled." This shows the wind is strong.\nStrong: The "bitter wind" that "howled" creates a hostile atmosphere, with "bitter" connoting resentment and suffering.\n\nRules:\n• Keep quotes SHORT (2–5 words).\n• Zoom into individual words within the quote for deeper analysis.\n• Your sentence must read fluently with the quote inside it.\n• Use quotation marks accurately.\n\nThis single skill separates Band 3 from Band 4 responses.' },
      { id: 'eet2-14', front: 'Planning Transactional Writing (Paper 1 Q5)', back: 'Spend 5 minutes planning. This is NOT wasted time — it prevents rambling.\n\nPlan format:\n1. Purpose: argue / persuade / advise / inform\n2. Audience: who am I writing to? (determines register)\n3. Form: letter / article / speech / review / blog / report\n4. Key points: 4–5 arguments or ideas (one per paragraph)\n5. Opening: hook — statistic, question, bold statement, anecdote\n6. Closing: call to action, circular reference to opening, powerful final line\n\nA planned essay with 4 strong points beats an unplanned essay with 7 weak ones.' },
      { id: 'eet2-15', front: 'Planning Imaginative Writing (Paper 2 Q5)', back: 'Spend 5 minutes planning. Choose SMALL and go DEEP.\n\nPlan format:\n1. Scenario: one scene, one moment, one character\n2. Setting: 3 sensory details to establish atmosphere\n3. Structure: opening → build tension → shift/turning point → climax → resolution\n4. Motif: one image or idea to repeat and develop\n5. Ending: how does it resolve? Echo the opening for cyclical structure.\n\nDo NOT try to tell a whole life story. The best responses zoom into 10 minutes of a character\'s life and make the reader FEEL it.' },
      { id: 'eet2-16', front: 'The 19th-Century Source — How to Approach It', back: 'Paper 1 always includes a 19th-century non-fiction text. Do not be intimidated.\n\nStrategy:\n1. Read it TWICE — once for gist, once for detail.\n2. Expect formal, complex sentences with subordinate clauses — this is normal.\n3. If a word is unfamiliar, infer from context.\n4. Consider the CONTEXT: industrialisation, empire, class, gender, religion, reform.\n5. Remember the writer\'s PURPOSE — 19th-century non-fiction was often written to campaign, argue, or persuade.\n\nThe 19th-century text is often richer for analysis than the modern source. Engage with it fully.' },
      { id: 'eet2-17', front: 'Common Mistakes and How to Avoid Them', back: '1. Feature-spotting: "The writer uses alliteration" — SO WHAT? Always explain the effect.\n2. Retelling: Do not narrate what happens. Analyse HOW and WHY the writer creates effects.\n3. Running out of time on Q5: Writing = 50% of the paper. Set a timer and protect writing time.\n4. Ignoring structure: Language-only analysis caps your mark on Paper 2 Q3. Always discuss structural choices.\n5. Wrong form conventions: A speech without direct address. A letter without a sign-off. Check your form.\n6. Single-word quotes only: Zoom in on words, but also quote phrases to show you understand context.\n7. No proofreading: 5 minutes of checking can gain 3–4 marks in AO6. Always leave time.' },
      { id: 'eet2-18', front: 'Upgrading Your Analytical Vocabulary', back: 'Replace generic words with precise analytical terms:\n\n• "shows" → "conveys," "implies," "suggests," "reveals," "foregrounds"\n• "the reader feels sad" → "evokes pathos," "elicits sympathy," "creates a sombre mood"\n• "is effective" → "is compelling," "resonates with the reader," "achieves its purpose"\n• "a good description" → "evocative imagery," "visceral sensory detail"\n• "the writer talks about" → "the writer interrogates," "the writer foregrounds," "the writer confronts"\n• "this is interesting" → NEVER write this. Explain WHY it is interesting.\n\nPrecise vocabulary signals Band 4–5 analysis to the examiner.' },
    ],
  },
  {
    id: 'macbeth-quotes',
    title: 'Macbeth — Key Quotations',
    description: '30 key quotations covering all major characters and themes',
    category: 'Literature',
    board: 'All',
    cards: [
      { id: 'mq-1', front: '"Fair is foul, and foul is fair"', back: 'Speaker: The Witches (Act 1, Scene 1)\n\nMeaning: What appears good is actually evil and vice versa. Sets the moral confusion of the entire play.\n\nTechniques: Chiasmus, paradox, antithesis.\n\nThemes: Appearance vs reality, the supernatural, moral disorder.\n\nExam point: This opening line establishes the play\'s central motif — that nothing in Macbeth\'s world can be trusted at face value, and Shakespeare uses the Witches to collapse the boundary between good and evil from the very first scene.' },
      { id: 'mq-2', front: '"Stars, hide your fires"', back: 'Speaker: Macbeth (Act 1, Scene 4)\n\nMeaning: Macbeth wants darkness to conceal his murderous ambitions from the world and from himself.\n\nTechniques: Apostrophe (addressing the stars), imperative, symbolism (stars = morality/divine order; darkness = evil).\n\nThemes: Ambition, appearance vs reality, light vs dark.\n\nExam point: Macbeth actively invites darkness, showing that his ambition is already corrupting him before any supernatural intervention — he chooses to hide from his own conscience.' },
      { id: 'mq-3', front: '"Look like th\'innocent flower, but be the serpent under\'t"', back: 'Speaker: Lady Macbeth to Macbeth (Act 1, Scene 5)\n\nMeaning: She instructs him to appear innocent while concealing murderous intent.\n\nTechniques: Simile, juxtaposition (flower vs serpent), biblical allusion (serpent = Satan in Eden).\n\nThemes: Appearance vs reality, deception, gender roles.\n\nExam point: Lady Macbeth takes the role of tempter, echoing the serpent of Genesis; Shakespeare positions her as the driving force behind Duncan\'s murder, subverting Jacobean expectations of feminine passivity.' },
      { id: 'mq-4', front: '"Unsex me here"', back: 'Speaker: Lady Macbeth (Act 1, Scene 5)\n\nMeaning: She calls on dark spirits to strip away her femininity so she can be ruthless enough to help murder Duncan.\n\nTechniques: Imperative, invocation, soliloquy.\n\nThemes: Gender roles, the supernatural, ambition, power.\n\nExam point: Shakespeare uses Lady Macbeth to challenge Jacobean gender norms — she believes cruelty is inherently masculine, and must reject her womanhood to act. This also foreshadows her psychological collapse, as the guilt she suppresses here later destroys her.' },
      { id: 'mq-5', front: '"Is this a dagger which I see before me"', back: 'Speaker: Macbeth (Act 2, Scene 1)\n\nMeaning: Macbeth hallucinates a dagger leading him toward Duncan\'s chamber, questioning his own sanity.\n\nTechniques: Rhetorical question, soliloquy, hallucination/symbolism.\n\nThemes: Guilt, the supernatural, ambition, psychological torment.\n\nExam point: The dagger symbolises Macbeth\'s wavering conscience — he cannot tell reality from illusion, suggesting guilt is already fracturing his mind before the murder is even committed.' },
      { id: 'mq-6', front: '"Will all great Neptune\'s ocean wash this blood clean from my hand?"', back: 'Speaker: Macbeth (Act 2, Scene 2)\n\nMeaning: Macbeth believes no amount of water can cleanse his guilt after killing Duncan.\n\nTechniques: Rhetorical question, hyperbole, allusion (Neptune = Roman god of the sea).\n\nThemes: Guilt, violence, moral corruption.\n\nExam point: The blood imagery recurs throughout the play as an ever-deepening symbol of guilt; here Macbeth recognises his sin is permanent, yet he continues to kill — showing ambition overpowers even unbearable remorse.' },
      { id: 'mq-7', front: '"A little water clears us of this deed"', back: 'Speaker: Lady Macbeth (Act 2, Scene 2)\n\nMeaning: She dismisses the murder as something easily concealed, contrasting sharply with Macbeth\'s despair.\n\nTechniques: Juxtaposition with Macbeth\'s "Neptune\'s ocean" line, understatement, irony.\n\nThemes: Guilt, appearance vs reality, gender roles.\n\nExam point: This line is deeply ironic given her later sleepwalking scene where she obsessively washes her hands — Shakespeare shows guilt cannot be suppressed forever, and her rational facade crumbles completely by Act 5.' },
      { id: 'mq-8', front: '"O, full of scorpions is my mind"', back: 'Speaker: Macbeth (Act 3, Scene 2)\n\nMeaning: Macbeth reveals his tormented psychological state — paranoia and guilt consume him.\n\nTechniques: Metaphor, exclamatory, imagery of poison/danger.\n\nThemes: Guilt, psychological torment, consequences of ambition.\n\nExam point: The scorpion metaphor suggests Macbeth\'s thoughts are venomous and self-destructive — his mind has become a prison of his own making, and the crown he fought for brings only suffering, not satisfaction.' },
      { id: 'mq-9', front: '"Blood will have blood"', back: 'Speaker: Macbeth (Act 3, Scene 4)\n\nMeaning: Violence begets more violence — murder demands retribution.\n\nTechniques: Proverbial language, repetition, foreshadowing.\n\nThemes: Violence, guilt, fate, the natural order.\n\nExam point: Macbeth recognises the cycle of violence he has entered but feels powerless to stop it; Shakespeare presents tyranny as self-perpetuating — each murder necessitates the next, trapping Macbeth in escalating bloodshed.' },
      { id: 'mq-10', front: '"I am in blood stepp\'d in so far"', back: 'Speaker: Macbeth (Act 3, Scene 4)\n\nMeaning: He has committed so many murders that turning back is as difficult as continuing.\n\nTechniques: Extended metaphor (wading through a river of blood), imagery.\n\nThemes: Guilt, moral corruption, the point of no return.\n\nExam point: This is Macbeth\'s moral nadir — he no longer agonises over right and wrong but calculates effort. Shakespeare shows how repeated sin erodes conscience until evil becomes the path of least resistance.' },
      { id: 'mq-11', front: '"Double, double toil and trouble"', back: 'Speaker: The Witches (Act 4, Scene 1)\n\nMeaning: The Witches chant as they brew their potion, summoning chaos and destruction.\n\nTechniques: Rhyming couplets, incantation, trochaic tetrameter (disrupts iambic pentameter).\n\nThemes: The supernatural, chaos, fate.\n\nExam point: Shakespeare gives the Witches a distinct, abnormal metre to set them apart from the human world — their broken rhythm reflects the disorder they bring, and would have terrified a Jacobean audience who believed in witchcraft.' },
      { id: 'mq-12', front: '"Out, damned spot!"', back: 'Speaker: Lady Macbeth (Act 5, Scene 1)\n\nMeaning: While sleepwalking, she hallucinates blood on her hands that she cannot wash away.\n\nTechniques: Exclamatory, symbolism (blood = guilt), dramatic irony (recalls "a little water" in Act 2).\n\nThemes: Guilt, madness, consequences of ambition.\n\nExam point: Shakespeare\'s dramatic irony is devastating — the woman who dismissed guilt so easily is now destroyed by it. Her sleepwalking reveals the subconscious truth she tried to repress, showing guilt is inescapable.' },
      { id: 'mq-13', front: '"What\'s done cannot be undone"', back: 'Speaker: Lady Macbeth (Act 5, Scene 1)\n\nMeaning: In her madness, she acknowledges the irreversibility of their crimes.\n\nTechniques: Dramatic irony (echoes her earlier "what\'s done is done" from Act 3), proverbial language.\n\nThemes: Guilt, fate, consequences.\n\nExam point: The shift from "what\'s done is done" (dismissive) to "what\'s done cannot be undone" (despairing) tracks Lady Macbeth\'s complete psychological collapse — Shakespeare shows guilt transforming certainty into hopelessness.' },
      { id: 'mq-14', front: '"By the pricking of my thumbs, something wicked this way comes"', back: 'Speaker: Second Witch (Act 4, Scene 1)\n\nMeaning: The Witches sense Macbeth approaching — even they call him "wicked."\n\nTechniques: Rhyming couplet, foreshadowing, dramatic irony.\n\nThemes: The supernatural, moral corruption, evil.\n\nExam point: When even the agents of darkness call Macbeth "wicked," Shakespeare signals his complete moral fall — he has surpassed his corrupters, becoming more evil than the supernatural forces that tempted him.' },
      { id: 'mq-15', front: '"Yet do I fear thy nature; it is too full o\' th\' milk of human kindness"', back: 'Speaker: Lady Macbeth (Act 1, Scene 5)\n\nMeaning: She fears Macbeth is too compassionate to seize the crown through murder.\n\nTechniques: Metaphor (milk = nurture, innocence), soliloquy.\n\nThemes: Gender roles, ambition, masculinity.\n\nExam point: Lady Macbeth equates kindness with weakness and masculinity with violence — Shakespeare exposes the toxic expectations she places on Macbeth, which ultimately drive both characters to destruction.' },
      { id: 'mq-16', front: '"So foul and fair a day I have not seen"', back: 'Speaker: Macbeth (Act 1, Scene 3)\n\nMeaning: Macbeth unknowingly echoes the Witches\' words, linking himself to their dark influence.\n\nTechniques: Dramatic irony, paradox, echoing.\n\nThemes: The supernatural, fate vs free will, appearance vs reality.\n\nExam point: Shakespeare connects Macbeth to the Witches before they even meet on stage, suggesting he is already predisposed to evil — raising the question of whether the Witches create his ambition or merely awaken what already exists.' },
      { id: 'mq-17', front: '"There\'s no art to find the mind\'s construction in the face"', back: 'Speaker: King Duncan (Act 1, Scene 4)\n\nMeaning: You cannot tell what someone is thinking by looking at their face.\n\nTechniques: Dramatic irony (he is about to trust Macbeth, who will murder him), proverbial.\n\nThemes: Appearance vs reality, trust, kingship.\n\nExam point: Duncan\'s inability to read treachery makes him a poor judge of character — Shakespeare uses this to show that goodness alone is insufficient for a king; Duncan\'s trusting nature is a fatal flaw in a world of deception.' },
      { id: 'mq-18', front: '"When you durst do it, then you were a man"', back: 'Speaker: Lady Macbeth to Macbeth (Act 1, Scene 7)\n\nMeaning: She questions his masculinity to manipulate him into committing the murder.\n\nTechniques: Manipulation, conditional clause, challenging tone.\n\nThemes: Gender roles, masculinity, power, ambition.\n\nExam point: Lady Macbeth weaponises Jacobean ideas of manhood to control Macbeth — Shakespeare shows how toxic masculinity becomes a tool of manipulation, and Macbeth\'s need to prove himself "a man" leads directly to regicide.' },
      { id: 'mq-19', front: '"Macbeth does murder sleep"', back: 'Speaker: Macbeth (Act 2, Scene 2)\n\nMeaning: After killing Duncan, Macbeth hears a voice declaring he has murdered sleep itself — he will never rest peacefully again.\n\nTechniques: Personification, symbolism (sleep = innocence, peace, natural order).\n\nThemes: Guilt, the natural order, consequences.\n\nExam point: Sleep represents the innocent conscience Macbeth has destroyed; Shakespeare uses insomnia as a physical manifestation of guilt that haunts both Macbeths — he cannot sleep, she sleepwalks.' },
      { id: 'mq-20', front: '"Thou canst not say I did it. Never shake thy gory locks at me"', back: 'Speaker: Macbeth to Banquo\'s ghost (Act 3, Scene 4)\n\nMeaning: Macbeth is terrified by Banquo\'s ghost at the banquet and tries to deny responsibility.\n\nTechniques: Dramatic irony (the guests cannot see the ghost), imperative, apostrophe.\n\nThemes: Guilt, the supernatural, consequences of violence.\n\nExam point: The ghost may be a supernatural visitation or a projection of Macbeth\'s guilt — either way, Shakespeare shows that Macbeth\'s crimes cannot be hidden; his public breakdown reveals the tyrant\'s inner collapse.' },
      { id: 'mq-21', front: '"Life\'s but a walking shadow, a poor player"', back: 'Speaker: Macbeth (Act 5, Scene 5)\n\nMeaning: Upon hearing of Lady Macbeth\'s death, Macbeth declares life is meaningless — like a bad actor on stage.\n\nTechniques: Metaphor, nihilism, meta-theatrical imagery.\n\nThemes: Fate, mortality, meaninglessness, despair.\n\nExam point: Shakespeare gives Macbeth a moment of tragic self-awareness — he recognises that his ambition has led to nothing. The theatre metaphor is especially powerful as the audience watches an actor playing a man who compares life to acting.' },
      { id: 'mq-22', front: '"It is a tale told by an idiot, full of sound and fury, signifying nothing"', back: 'Speaker: Macbeth (Act 5, Scene 5)\n\nMeaning: Life is a meaningless story — full of noise but ultimately empty.\n\nTechniques: Metaphor, nihilistic tone, plosive sounds ("told," "tale," "fury").\n\nThemes: Meaninglessness, despair, mortality.\n\nExam point: This is Macbeth\'s darkest conclusion — his pursuit of power has drained life of all meaning. Shakespeare presents this as the inevitable end of unchecked ambition: not glory, but existential emptiness.' },
      { id: 'mq-23', front: '"I have no spur to prick the sides of my intent"', back: 'Speaker: Macbeth (Act 1, Scene 7)\n\nMeaning: Macbeth admits the only thing driving him to murder is "vaulting ambition" — he has no moral justification.\n\nTechniques: Extended metaphor (horse-riding), soliloquy.\n\nThemes: Ambition, moral conflict, free will.\n\nExam point: This soliloquy is crucial because Macbeth rationally lists every reason NOT to kill Duncan and finds only ambition as a motive — Shakespeare shows the murder is a conscious, unjustifiable choice, not fate.' },
      { id: 'mq-24', front: '"Nought\'s had, all\'s spent, where our desire is got without content"', back: 'Speaker: Lady Macbeth (Act 3, Scene 2)\n\nMeaning: They have gained everything they wanted but find no happiness — it was all for nothing.\n\nTechniques: Antithesis ("had" / "spent"), rhyming couplet, paradox.\n\nThemes: Ambition, dissatisfaction, consequences.\n\nExam point: Lady Macbeth articulates the play\'s central moral — ambition achieved through evil brings no fulfilment. Shakespeare uses her private admission to contrast with her public confidence, showing the cracks forming early.' },
      { id: 'mq-25', front: '"He\'s here in double trust"', back: 'Speaker: Macbeth (Act 1, Scene 7)\n\nMeaning: Macbeth acknowledges Duncan trusts him as both his kinsman and his host — making the murder doubly treacherous.\n\nTechniques: Dramatic irony, soliloquy.\n\nThemes: Loyalty, betrayal, kingship, the natural order.\n\nExam point: Macbeth\'s awareness of Duncan\'s trust makes his crime even more horrific — Shakespeare emphasises that this is not ignorant evil but deliberate betrayal of sacred bonds of kinship and hospitality.' },
      { id: 'mq-26', front: '"The instruments of darkness tell us truths"', back: 'Speaker: Banquo (Act 1, Scene 3)\n\nMeaning: Banquo warns that evil forces use partial truths to lead people to destruction.\n\nTechniques: Metaphor ("instruments of darkness"), foreshadowing.\n\nThemes: The supernatural, appearance vs reality, fate vs free will.\n\nExam point: Banquo serves as Macbeth\'s moral foil — he hears the same prophecy but chooses caution over action. Shakespeare uses Banquo to show that the Witches\' power lies in manipulation, not compulsion.' },
      { id: 'mq-27', front: '"I dare do all that may become a man"', back: 'Speaker: Macbeth to Lady Macbeth (Act 1, Scene 7)\n\nMeaning: Macbeth argues that true manhood means knowing the limits of acceptable behaviour.\n\nTechniques: Declarative, defining statement.\n\nThemes: Masculinity, honour, moral boundaries.\n\nExam point: Macbeth briefly offers a healthier vision of masculinity — one defined by restraint, not violence. Shakespeare shows this moral clarity is quickly overwhelmed by Lady Macbeth\'s manipulation, suggesting societal pressure overrides individual conscience.' },
      { id: 'mq-28', front: '"O, O, O!"', back: 'Speaker: Lady Macbeth (Act 5, Scene 1)\n\nMeaning: Lady Macbeth\'s anguished cries during her sleepwalking — language has failed her.\n\nTechniques: Exclamatory, fragmentation, non-verbal expression.\n\nThemes: Guilt, madness, the collapse of control.\n\nExam point: The woman who commanded language so powerfully in Act 1 is reduced to incoherent moaning — Shakespeare shows guilt has stripped her of the eloquence that was her greatest weapon, mirroring her total psychological disintegration.' },
      { id: 'mq-29', front: '"This dead butcher and his fiend-like queen"', back: 'Speaker: Malcolm (Act 5, Scene 8)\n\nMeaning: Malcolm dismisses Macbeth as a mere butcher and Lady Macbeth as a devil.\n\nTechniques: Epithet, reductive language, political rhetoric.\n\nThemes: Kingship, legacy, justice.\n\nExam point: Malcolm\'s verdict is politically convenient but reductive — Shakespeare invites the audience to question this summary. We have seen Macbeth\'s conscience and Lady Macbeth\'s suffering; they are more complex than "butcher" and "fiend," making this a statement about how history simplifies.' },
      { id: 'mq-30', front: '"Screw your courage to the sticking-place"', back: 'Speaker: Lady Macbeth (Act 1, Scene 7)\n\nMeaning: She tells Macbeth to tighten his resolve — commit fully to the murder.\n\nTechniques: Metaphor (from crossbow mechanics — winding to full tension), imperative.\n\nThemes: Ambition, manipulation, gender roles.\n\nExam point: Lady Macbeth uses a mechanical metaphor to reduce murder to a practical task — Shakespeare shows her ability to strip moral weight from violence, making the unthinkable feel like simple determination.' },
    ],
  },
  {
    id: 'romeo-juliet-quotes',
    title: 'Romeo & Juliet — Key Quotations',
    description: '30 key quotations covering all major characters and themes',
    category: 'Literature',
    board: 'All',
    cards: [
      { id: 'rj-1', front: '"Two households, both alike in dignity"', back: 'Speaker: Chorus / Prologue\n\nMeaning: Two equally noble families are locked in a feud. The Prologue reveals the lovers will die, framing the play as inevitable tragedy.\n\nTechniques: Sonnet form, dramatic irony, foreshadowing ("star-cross\'d lovers").\n\nThemes: Fate, conflict, family/honour.\n\nExam point: Shakespeare removes suspense by revealing the ending upfront — the audience watches knowing the lovers are doomed, creating dramatic irony that makes every hopeful moment painful.' },
      { id: 'rj-2', front: '"O brawling love, O loving hate"', back: 'Speaker: Romeo (Act 1, Scene 1)\n\nMeaning: Romeo describes the confusing contradictions of love using a string of oxymorons.\n\nTechniques: Oxymoron, antithesis, exclamatory.\n\nThemes: Love, conflict, confusion.\n\nExam point: Romeo\'s oxymorons reflect the play\'s central paradox — love and hate are inseparable in Verona. Shakespeare establishes early that love in this world is bound up with violence, foreshadowing the tragic outcome.' },
      { id: 'rj-3', front: '"Did my heart love till now?"', back: 'Speaker: Romeo (Act 1, Scene 5)\n\nMeaning: Upon seeing Juliet for the first time, Romeo questions whether he has ever truly loved before.\n\nTechniques: Rhetorical question, volta (turning point from Rosaline to Juliet).\n\nThemes: Love at first sight, the nature of love.\n\nExam point: Shakespeare uses this rhetorical question to mark Romeo\'s transformation — his love for Rosaline was performative and conventional, but Juliet provokes genuine feeling. However, the speed of this shift also suggests Romeo\'s love is impulsive.' },
      { id: 'rj-4', front: '"But soft, what light through yonder window breaks?"', back: 'Speaker: Romeo (Act 2, Scene 2 — the balcony scene)\n\nMeaning: Romeo sees Juliet at her window and compares her to the rising sun.\n\nTechniques: Light imagery, metaphor (Juliet = sun), soliloquy.\n\nThemes: Love, light vs dark, idealism.\n\nExam point: Shakespeare associates Juliet with celestial light throughout the play — she is Romeo\'s source of illumination in a dark world. This imagery also makes her death more devastating: when Juliet dies, Romeo\'s light is extinguished.' },
      { id: 'rj-5', front: '"What\'s in a name?"', back: 'Speaker: Juliet (Act 2, Scene 2)\n\nMeaning: Juliet argues that names are arbitrary labels — Romeo is still the same person regardless of being a Montague.\n\nTechniques: Rhetorical question, philosophical argument.\n\nThemes: Identity, family/honour, love vs society.\n\nExam point: Juliet shows more intellectual maturity than Romeo here — she rationally deconstructs the feud\'s logic. Shakespeare uses her to expose the absurdity of the conflict: the hatred is based on a name, not any real difference.' },
      { id: 'rj-6', front: '"A rose by any other name would smell as sweet"', back: 'Speaker: Juliet (Act 2, Scene 2)\n\nMeaning: A name does not change the nature of a thing — Romeo would be just as worthy if he were not called Montague.\n\nTechniques: Metaphor, analogy, symbolism (rose = beauty, love).\n\nThemes: Identity, love, the superficiality of the feud.\n\nExam point: Shakespeare uses natural imagery to argue that love is organic and real, while names and feuds are artificial constructs — yet these constructs ultimately destroy the lovers, showing society\'s power over the individual.' },
      { id: 'rj-7', front: '"These violent delights have violent ends"', back: 'Speaker: Friar Lawrence (Act 2, Scene 6)\n\nMeaning: Passionate, intense love can lead to destruction — he warns the lovers to be moderate.\n\nTechniques: Foreshadowing, antithesis, proverbial wisdom.\n\nThemes: Fate, love and death, haste.\n\nExam point: Friar Lawrence acts as a choric voice, articulating the play\'s moral. Shakespeare uses him to warn that the lovers\' intensity — their "violent delights" — carries the seeds of its own destruction, linking passion directly to death.' },
      { id: 'rj-8', front: '"My only love sprung from my only hate"', back: 'Speaker: Juliet (Act 1, Scene 5)\n\nMeaning: Juliet discovers Romeo is a Montague — the one person she loves belongs to the family she should hate.\n\nTechniques: Antithesis (love/hate), rhyming couplet, dramatic irony.\n\nThemes: Love vs hate, fate, conflict.\n\nExam point: This rhyming couplet crystallises the play\'s central tension — love and hate are born from the same source. Shakespeare makes the audience feel the cruel irony: in any other circumstances, this love would be celebrated.' },
      { id: 'rj-9', front: '"O, I am fortune\'s fool!"', back: 'Speaker: Romeo (Act 3, Scene 1)\n\nMeaning: After killing Tybalt, Romeo realises fate has trapped him — his impulsive action has sealed his doom.\n\nTechniques: Exclamatory, personification of fortune, alliteration.\n\nThemes: Fate, impulsiveness, tragedy.\n\nExam point: This is the play\'s turning point — Romeo shifts from lover to killer. Shakespeare leaves it ambiguous whether Romeo is truly fate\'s victim or whether his own impulsiveness is to blame, creating a tension between fate and free will.' },
      { id: 'rj-10', front: '"A plague o\' both your houses!"', back: 'Speaker: Mercutio (Act 3, Scene 1)\n\nMeaning: As he dies, Mercutio curses both the Montagues and Capulets for their senseless feud.\n\nTechniques: Curse, repetition (said three times), exclamatory.\n\nThemes: Conflict, consequences, blame.\n\nExam point: Mercutio — who belongs to neither family — is the feud\'s most innocent victim. His repeated curse becomes prophetic: both houses do suffer a "plague" of death. Shakespeare uses him to voice the audience\'s frustration at the pointless violence.' },
      { id: 'rj-11', front: '"Wisely and slow. They stumble that run fast"', back: 'Speaker: Friar Lawrence (Act 2, Scene 3)\n\nMeaning: The Friar advises caution — rushing leads to mistakes.\n\nTechniques: Imperative, proverbial wisdom, foreshadowing.\n\nThemes: Haste, fate, youth vs age.\n\nExam point: Friar Lawrence\'s advice is ignored by every young character — Romeo, Juliet, and Tybalt all act on impulse. Shakespeare contrasts the Friar\'s wisdom with the lovers\' recklessness to show that youth\'s intensity, while beautiful, is also fatally dangerous.' },
      { id: 'rj-12', front: '"It is the east, and Juliet is the sun"', back: 'Speaker: Romeo (Act 2, Scene 2)\n\nMeaning: Romeo compares Juliet to the sun — she outshines everything else.\n\nTechniques: Metaphor, celestial imagery, hyperbole.\n\nThemes: Love, light vs dark, idealism.\n\nExam point: Shakespeare elevates Juliet to a cosmic force — she is not merely beautiful but life-giving. This idealisation is romantic but also reveals Romeo\'s tendency to worship from afar, replacing one unattainable ideal (Rosaline) with another.' },
      { id: 'rj-13', front: '"Then I defy you, stars!"', back: 'Speaker: Romeo (Act 5, Scene 1)\n\nMeaning: Upon hearing of Juliet\'s "death," Romeo declares he will fight against fate itself.\n\nTechniques: Exclamatory, apostrophe, defiance, dramatic irony.\n\nThemes: Fate, free will, impulsiveness.\n\nExam point: Romeo\'s defiance of fate is tragically futile — by rushing to die beside Juliet, he fulfils the very fate he tries to resist. Shakespeare shows that the attempt to escape destiny is itself part of the destined pattern.' },
      { id: 'rj-14', front: '"For never was a story of more woe"', back: 'Speaker: Prince Escalus (Act 5, Scene 3)\n\nMeaning: The Prince delivers the final judgement — this is the saddest story ever told, caused by hatred.\n\nTechniques: Rhyming couplet, superlative, elegiac tone.\n\nThemes: Tragedy, consequences of conflict, loss.\n\nExam point: The Prince speaks for the audience and for Verona — Shakespeare uses this closing couplet to ensure the play ends not with romantic sentiment but with a clear moral: the feud caused these deaths, and the whole community bears responsibility.' },
      { id: 'rj-15', front: '"O, she doth teach the torches to burn bright"', back: 'Speaker: Romeo (Act 1, Scene 5)\n\nMeaning: Juliet\'s beauty outshines every torch in the room — she makes light itself look dim.\n\nTechniques: Hyperbole, personification, alliteration, light imagery.\n\nThemes: Love at first sight, beauty, light vs dark.\n\nExam point: Shakespeare uses this moment to show love as an overwhelming, instantaneous force. The light imagery that will follow Romeo and Juliet throughout the play begins here — they are bright flames in a dark world, beautiful but destined to burn out.' },
      { id: 'rj-16', front: '"My bounty is as boundless as the sea"', back: 'Speaker: Juliet (Act 2, Scene 2)\n\nMeaning: Her love is infinite — the more she gives, the more she has.\n\nTechniques: Simile, hyperbole, sibilance.\n\nThemes: Love, generosity, passion.\n\nExam point: Juliet\'s language here is mature and generous — she sees love as expansive, not possessive. Shakespeare gives Juliet some of the play\'s most profound lines about love, positioning her as more emotionally intelligent than Romeo despite being younger.' },
      { id: 'rj-17', front: '"Women may fall when there\'s no strength in men"', back: 'Speaker: Friar Lawrence (Act 2, Scene 3)\n\nMeaning: The Friar criticises Romeo\'s fickleness — moving from Rosaline to Juliet so quickly.\n\nTechniques: Proverbial, accusatory, gender commentary.\n\nThemes: Love, fickleness, youth, gender.\n\nExam point: Shakespeare uses the Friar to question the sincerity of Romeo\'s love — is this genuine transformation or another infatuation? This ambiguity enriches the play: the audience must decide whether Romeo\'s love has truly matured or simply found a new object.' },
      { id: 'rj-18', front: '"Tempt not a desperate man"', back: 'Speaker: Romeo (Act 5, Scene 3)\n\nMeaning: Romeo warns Paris not to provoke him — he has nothing left to lose.\n\nTechniques: Imperative, foreshadowing, threatening tone.\n\nThemes: Desperation, fate, violence.\n\nExam point: Shakespeare shows Romeo at his most dangerous — grief has stripped away his gentleness. This line reveals how love and violence are intertwined in Verona: Romeo kills Paris out of the same passion that drives his love for Juliet.' },
      { id: 'rj-19', front: '"O happy dagger!"', back: 'Speaker: Juliet (Act 5, Scene 3)\n\nMeaning: Juliet finds Romeo\'s dagger and calls it "happy" because it will reunite her with him through death.\n\nTechniques: Oxymoron (happy/dagger), personification, dramatic irony.\n\nThemes: Love and death, fate, sacrifice.\n\nExam point: The oxymoron "happy dagger" encapsulates the play\'s fusion of love and death — the instrument of violence becomes an instrument of love. Shakespeare shows that in Verona\'s toxic world, death is the only space where the lovers can be together.' },
      { id: 'rj-20', front: '"Give me my Romeo, and when I shall die, take him and cut him out in little stars"', back: 'Speaker: Juliet (Act 3, Scene 2)\n\nMeaning: Juliet imagines Romeo\'s beauty scattered across the night sky as stars after death.\n\nTechniques: Celestial imagery, foreshadowing death, epithalamium (wedding-night speech).\n\nThemes: Love, death, light vs dark, immortality.\n\nExam point: Shakespeare foreshadows Romeo\'s death even in Juliet\'s most romantic speech — she can only imagine preserving his beauty through death. Love and death are fused in her language, anticipating the final scene where she joins him in death.' },
      { id: 'rj-21', front: '"Parting is such sweet sorrow"', back: 'Speaker: Juliet (Act 2, Scene 2)\n\nMeaning: Saying goodbye is painful yet also sweet because it means they will meet again.\n\nTechniques: Oxymoron, sibilance.\n\nThemes: Love, contradiction, bittersweet emotion.\n\nExam point: This famous oxymoron captures the play\'s essence — every sweet moment carries sorrow. Shakespeare shows that even at their happiest, the lovers\' joy is inseparable from pain, mirroring the play\'s structure where every moment of hope precedes disaster.' },
      { id: 'rj-22', front: '"I would the fool were married to her grave"', back: 'Speaker: Lady Capulet (Act 3, Scene 5)\n\nMeaning: Lady Capulet wishes Juliet were dead rather than disobedient.\n\nTechniques: Dramatic irony (Juliet does end up in a grave), foreshadowing, hyperbole.\n\nThemes: Family, patriarchal authority, fate.\n\nExam point: Shakespeare makes Lady Capulet unwittingly prophesy her daughter\'s death — this chilling dramatic irony shows how the parents\' rigidity and cruelty drive the tragedy. Their inability to listen becomes a death sentence.' },
      { id: 'rj-23', front: '"Hang thee, young baggage! Disobedient wretch!"', back: 'Speaker: Lord Capulet (Act 3, Scene 5)\n\nMeaning: Capulet rages at Juliet for refusing to marry Paris, threatening to disown her.\n\nTechniques: Exclamatory, insults, imperatives, plosive sounds.\n\nThemes: Patriarchal authority, family, gender, power.\n\nExam point: Capulet\'s verbal violence reveals the patriarchal tyranny beneath his earlier affection — Shakespeare shows that Juliet is property to be disposed of, not a person with agency. His rage pushes Juliet toward the desperate plan that kills her.' },
      { id: 'rj-24', front: '"Peace? I hate the word"', back: 'Speaker: Tybalt (Act 1, Scene 1)\n\nMeaning: Tybalt rejects any possibility of peace — he lives for the feud.\n\nTechniques: Minor sentence, declarative, aggressive tone.\n\nThemes: Conflict, honour, masculinity.\n\nExam point: Shakespeare establishes Tybalt as the embodiment of the feud\'s violence — his hatred is not rational but instinctive. He represents the toxic honour culture that makes peace impossible and ultimately kills the lovers.' },
      { id: 'rj-25', front: '"Thus with a kiss I die"', back: 'Speaker: Romeo (Act 5, Scene 3)\n\nMeaning: Romeo kisses Juliet one final time before drinking the poison.\n\nTechniques: Dramatic irony (Juliet is alive), juxtaposition (kiss/death), simple language.\n\nThemes: Love and death, fate, tragedy.\n\nExam point: Shakespeare unites love and death in a single action — the kiss is both an act of love and a farewell to life. The simplicity of the language makes it devastating; Romeo needs no elaborate poetry, only this final gesture.' },
      { id: 'rj-26', front: '"Death, that hath suck\'d the honey of thy breath"', back: 'Speaker: Romeo (Act 5, Scene 3)\n\nMeaning: Romeo notices Juliet still looks beautiful in "death" — death has taken her life but not her beauty.\n\nTechniques: Personification of death, sensory imagery, dramatic irony (she is alive).\n\nThemes: Love, death, beauty, fate.\n\nExam point: The dramatic irony is excruciating — Romeo observes signs of life (her beauty, her colour) but interprets them through the lens of death. Shakespeare shows how close he comes to the truth, making the tragedy feel preventable and therefore more painful.' },
      { id: 'rj-27', front: '"All are punish\'d"', back: 'Speaker: Prince Escalus (Act 5, Scene 3)\n\nMeaning: Everyone has suffered because of the feud — no one escapes punishment.\n\nTechniques: Declarative, universal judgement, passive voice.\n\nThemes: Consequences, justice, collective responsibility.\n\nExam point: The Prince includes himself in the blame — his failure to enforce peace enabled the deaths. Shakespeare shows tragedy is never caused by one person; it is the product of an entire society\'s failures, from parents to rulers to bystanders.' },
      { id: 'rj-28', front: '"From forth the fatal loins of these two foes"', back: 'Speaker: Chorus / Prologue\n\nMeaning: From these two enemy families, the doomed lovers are born.\n\nTechniques: Alliteration ("forth," "fatal," "foes"), foreshadowing, sonnet form.\n\nThemes: Fate, family, death.\n\nExam point: The alliterative "f" sounds create a driving, relentless rhythm that mirrors fate\'s inescapable force. Shakespeare connects birth ("loins") with death ("fatal"), suggesting the lovers\' doom is literally genetic — they are born into a conflict that will kill them.' },
      { id: 'rj-29', front: '"O, swear not by the moon, th\' inconstant moon"', back: 'Speaker: Juliet (Act 2, Scene 2)\n\nMeaning: Juliet warns Romeo not to swear by the moon because it changes — she wants constant, reliable love.\n\nTechniques: Imperative, symbolism (moon = changeability), foreshadowing.\n\nThemes: Love, constancy vs fickleness, youth.\n\nExam point: Juliet is more practical and clear-sighted than Romeo — she sees through romantic gestures to demand real commitment. Shakespeare gives her the intellectual authority in their relationship, challenging the convention that women are passive objects of love.' },
      { id: 'rj-30', front: '"A pair of star-cross\'d lovers take their life"', back: 'Speaker: Chorus / Prologue\n\nMeaning: Two lovers, fated by the stars to fail, will kill themselves.\n\nTechniques: Compound adjective ("star-cross\'d"), foreshadowing, double meaning ("take their life" = live and die).\n\nThemes: Fate, love, death, tragedy.\n\nExam point: "Star-cross\'d" is Shakespeare\'s most famous image of doomed love — the stars (fate) have crossed out their happiness. The phrase also invokes astrology, which Elizabethans took seriously, suggesting the lovers never had a chance. The ambiguity of "take their life" — meaning both to begin life together and to end it — encapsulates the play\'s fusion of love and death.' },
    ],
  },
  {
    id: 'acc-comprehensive',
    title: 'A Christmas Carol — Comprehensive Study',
    description: '40 exam-ready flashcards covering key quotations, characters, themes, and context for A Christmas Carol',
    category: 'Literature',
    board: 'All',
    cards: [
      // ===== QUOTATION CARDS (15) =====
      { id: 'acc-q1', front: '"Oh! But he was a tight-fisted hand at the grindstone, Scrooge!"', back: 'Stave: One (Marley\'s Ghost)\nSpeaker/Narrator: Third-person narrator\nTechnique: Exclamatory, metaphor ("grindstone" implies relentless, mechanical labour for profit), direct address to the reader ("Oh!")\nTheme: Greed and miserliness\n\nAnalysis: Dickens opens his characterisation of Scrooge with a visceral metaphor — the "grindstone" suggests he squeezes every last penny from others with industrial efficiency. The narrator\'s exclamatory tone ("Oh!") creates a conversational, almost gossipy rapport with the reader, inviting us to judge Scrooge from the outset. This sets up the moral framework of the novella: Scrooge embodies everything Dickens wants Victorian society to reject.' },
      { id: 'acc-q2', front: '"Bah! Humbug!"', back: 'Stave: One (Marley\'s Ghost)\nSpeaker: Ebenezer Scrooge\nTechnique: Exclamatory, dismissive tone, minor sentence/fragment\nTheme: Isolation, rejection of Christmas spirit\n\nAnalysis: Scrooge\'s iconic catchphrase is a blunt rejection of Christmas joy. "Humbug" means fraud or nonsense — Scrooge sees generosity and celebration as a deception. The brevity of the exclamation mirrors his emotional barrenness; he has no time for warmth or connection. Dickens uses this to represent the attitude of the wealthy Victorians who dismissed charity as pointless sentimentality.' },
      { id: 'acc-q3', front: '"Are there no prisons? Are there no workhouses?"', back: 'Stave: One (Marley\'s Ghost)\nSpeaker: Ebenezer Scrooge\nTechnique: Rhetorical questions, repetition, callous tone\nTheme: Social responsibility, poverty, class\n\nAnalysis: Scrooge deflects responsibility for the poor by pointing to institutions that Dickens\'s readers would recognise as cruel and dehumanising. The rhetorical questions imply he believes the poor are already "dealt with." Dickens directly critiques the 1834 Poor Law and the Malthusian attitude that poverty was the fault of the poor. These words return to haunt Scrooge via the Ghost of Christmas Present, turning his own logic against him.' },
      { id: 'acc-q4', front: '"I wear the chain I forged in life"', back: 'Stave: One (Marley\'s Ghost)\nSpeaker: Jacob Marley\'s Ghost\nTechnique: Metaphor (chain = accumulated sins), first person, past tense ("forged")\nTheme: Consequences, redemption, greed\n\nAnalysis: Marley\'s chain is a powerful symbol — each link represents a selfish act during his lifetime. The verb "forged" has connotations of heavy industry, linking sin to the dehumanising capitalism of the era. Marley serves as a prophetic mirror for Scrooge: his punishment is to wander the earth burdened by the weight of his own greed. Dickens implies that moral debts, unlike financial ones, cannot be escaped after death.' },
      { id: 'acc-q5', front: '"Mankind was my business"', back: 'Stave: One (Marley\'s Ghost)\nSpeaker: Jacob Marley\'s Ghost\nTechnique: Declarative, irony (he ignored "mankind" in life), emotive language\nTheme: Social responsibility, redemption\n\nAnalysis: Marley realises too late that caring for others — not making money — was his true "business." Dickens uses the word "business" with bitter irony: Marley spent his life obsessed with commerce, yet the only business that mattered was compassion. This line is the moral thesis of the entire novella and directly challenges the Victorian belief that charity was not the concern of businessmen.' },
      { id: 'acc-q6', front: '"A solitary child, neglected by his friends"', back: 'Stave: Two (The First of the Three Spirits)\nSpeaker/Narrator: Third-person narrator describing young Scrooge\nTechnique: Pathetic imagery, isolation motif, adjective "solitary"\nTheme: Isolation, childhood, empathy\n\nAnalysis: This moment is the turning point in reader sympathy. Dickens shows that Scrooge\'s coldness has roots in childhood neglect and loneliness. The adjective "solitary" will echo through the novella — Scrooge chose isolation as an adult because it was all he knew as a child. Dickens encourages the Victorian reader to see that cruelty often stems from suffering, and that compassion, not punishment, is the remedy.' },
      { id: 'acc-q7', front: '"Another idol has displaced me... a golden one"', back: 'Stave: Two (The First of the Three Spirits)\nSpeaker: Belle (Scrooge\'s former fiancee)\nTechnique: Metaphor (idol = money worshipped like a god), allusion to biblical idolatry\nTheme: Greed vs love, loss, moral corruption\n\nAnalysis: Belle accuses Scrooge of replacing her with money — the "golden idol" alludes to the biblical golden calf, making Scrooge\'s worship of wealth a form of sin. Dickens shows that the pursuit of money costs Scrooge his only chance at love and family. Belle\'s departure marks the moment Scrooge chose isolation over connection, and he must witness it again to understand what he lost.' },
      { id: 'acc-q8', front: '"God bless us, every one!"', back: 'Stave: Three (The Second of the Three Spirits) and Stave Five\nSpeaker: Tiny Tim\nTechnique: Exclamatory, inclusive language ("every one"), religious register\nTheme: Generosity, family, Christian charity, hope\n\nAnalysis: Tiny Tim\'s blessing is the moral heart of the novella. "Every one" is radically inclusive — it extends goodwill even to those like Scrooge who would let him die. The religious language reinforces Dickens\'s Christian message that compassion must be universal. Tim\'s innocence and generosity despite poverty shames the wealthy who hoard their resources. His words bookend the novella, showing that Scrooge has adopted Tim\'s philosophy by Stave Five.' },
      { id: 'acc-q9', front: '"If he be like to die, he had better do it, and decrease the surplus population"', back: 'Stave: One (Marley\'s Ghost) — echoed in Stave Three\nSpeaker: Scrooge (original); Ghost of Christmas Present (quoting Scrooge back to him)\nTechnique: Callous tone, Malthusian language ("surplus population"), dramatic irony\nTheme: Social responsibility, poverty, consequences of indifference\n\nAnalysis: Scrooge parrots Thomas Malthus\'s theory that overpopulation causes poverty — a view many wealthy Victorians used to justify inaction. When the Ghost of Christmas Present throws these words back at Scrooge in reference to Tiny Tim, the abstraction becomes personal. Dickens forces both Scrooge and the reader to confront the human cost of such ideology: it is not "surplus population" but a real, beloved child who will die.' },
      { id: 'acc-q10', front: '"This boy is Ignorance. This girl is Want."', back: 'Stave: Three (The Second of the Three Spirits)\nSpeaker: Ghost of Christmas Present\nTechnique: Allegory, personification, declarative sentences, capitalisation of abstract nouns\nTheme: Social responsibility, education, poverty\n\nAnalysis: The two wretched children clinging to the Ghost\'s robes are allegorical — they represent the consequences of society\'s neglect. Dickens capitalises "Ignorance" and "Want" to make them universal forces, not individual failings. The Ghost warns: "Most of all beware this boy" (Ignorance), because an uneducated populace will destroy society. Dickens directly advocates for education reform and challenges the idea that poverty is the poor\'s own fault.' },
      { id: 'acc-q11', front: '"I am as light as a feather, I am as happy as an angel"', back: 'Stave: Five (The End of It)\nSpeaker: Ebenezer Scrooge\nTechnique: Similes, tricolon (the full line continues with a third comparison), joyful tone, transformation\nTheme: Redemption, joy, transformation\n\nAnalysis: Scrooge\'s language is utterly transformed — from blunt, monosyllabic dismissals to effusive, childlike similes. The "feather" suggests his burden of guilt has been lifted; the "angel" connects his newfound joy to spiritual salvation. The tricolon structure creates a breathless, giddy rhythm that mirrors Scrooge\'s overwhelming relief. Dickens shows that redemption is not solemn but joyous — it restores a person to their truest, happiest self.' },
      { id: 'acc-q12', front: '"Solitary as an oyster"', back: 'Stave: One (Marley\'s Ghost)\nSpeaker/Narrator: Third-person narrator\nTechnique: Simile, symbolism\nTheme: Isolation, greed\n\nAnalysis: The oyster simile works on multiple levels: oysters are closed, hard-shelled, and impenetrable — like Scrooge\'s emotional walls. But oysters also contain pearls, hinting that something valuable is hidden inside Scrooge if he can be opened. Dickens signals from the start that Scrooge is not irredeemable — his goodness is locked away, waiting to be released. This optimistic undercurrent drives the novella\'s redemption narrative.' },
      { id: 'acc-q13', front: '"Old Marley was as dead as a door-nail"', back: 'Stave: One (Marley\'s Ghost) — opening line\nSpeaker/Narrator: Third-person narrator\nTechnique: Simile, colloquial idiom, dark humour, direct address to reader\nTheme: Death, the supernatural\n\nAnalysis: Dickens opens with a comic, matter-of-fact declaration of death, establishing the novella\'s tone: serious moral themes delivered with wit and warmth. The narrator then playfully digresses about why door-nails are considered dead, creating an intimate, storytelling voice. Establishing Marley\'s death is essential — the reader must believe Marley is truly dead for his ghostly return to carry weight.' },
      { id: 'acc-q14', front: '"The cold within him froze his old features"', back: 'Stave: One (Marley\'s Ghost)\nSpeaker/Narrator: Third-person narrator\nTechnique: Metaphor, pathetic fallacy (internal weather), semantic field of cold\nTheme: Isolation, emotional coldness\n\nAnalysis: Dickens externalises Scrooge\'s inner nature — the cold is not from the weather but from within his soul. This internal pathetic fallacy links Scrooge\'s emotional state to his physical appearance, suggesting that cruelty visibly corrupts a person. The semantic field of cold and ice runs throughout Stave One and only thaws as Scrooge transforms, creating a structural motif that mirrors his redemption arc.' },
      { id: 'acc-q15', front: '"He became as good a friend, as good a master, and as good a man"', back: 'Stave: Five (The End of It)\nSpeaker/Narrator: Third-person narrator\nTechnique: Tricolon, anaphora ("as good a"), declarative\nTheme: Redemption, social responsibility, generosity\n\nAnalysis: The tricolon summarises Scrooge\'s complete transformation across three social roles: friend (personal), master (professional/economic), and man (moral/universal). The anaphora of "as good a" hammers home that Scrooge\'s change is not partial — it touches every aspect of his life. Dickens\'s message is that individual moral transformation can heal society: if one man changes, he improves the lives of everyone around him.' },

      // ===== CHARACTER CARDS (10) =====
      { id: 'acc-c1', front: 'Ebenezer Scrooge', back: 'Role: Protagonist — a wealthy, miserly London moneylender who despises Christmas and refuses to help the poor.\n\nKey Quotes:\n• "Bah! Humbug!" — dismisses Christmas joy\n• "Solitary as an oyster" — isolated but containing hidden goodness\n• "I am as light as a feather" — transformed, joyful\n\nDevelopment Arc: Scrooge undergoes the novella\'s central transformation. He begins as cold, isolated, and cruel (Stave 1), is forced to confront his past pain (Stave 2), witness the consequences of his indifference (Staves 3-4), and ultimately chooses redemption (Stave 5). His arc moves from isolation to community, greed to generosity.\n\nExaminer Tip: Always link Scrooge to Dickens\'s wider social message — he represents the wealthy Victorians Dickens wanted to change. His redemption proves that individual moral transformation can address social injustice. Frame his journey as Dickens\'s argument that compassion is a choice available to everyone.' },
      { id: 'acc-c2', front: 'Bob Cratchit', back: 'Role: Scrooge\'s underpaid clerk — represents the honest, hardworking poor exploited by the wealthy.\n\nKey Quotes:\n• Described working with a "comforter" because Scrooge won\'t pay for coal\n• Toasts Scrooge as "the Founder of the Feast" despite mistreatment\n• His family is loving despite poverty\n\nDevelopment Arc: Bob does not change — he is a moral constant. His goodness, loyalty, and warmth despite suffering serve as a foil to Scrooge. He endures exploitation without bitterness.\n\nExaminer Tip: Bob represents the "deserving poor" — Dickens uses him to argue that poverty is caused by unjust employers, not laziness. His willingness to toast Scrooge shows extraordinary grace, shaming the reader into recognising how the poor are treated. Link Bob to Dickens\'s critique of Victorian labour conditions and low wages.' },
      { id: 'acc-c3', front: 'Tiny Tim', back: 'Role: Bob Cratchit\'s youngest son — disabled, sickly, but full of joy and Christian charity.\n\nKey Quotes:\n• "God bless us, every one!" — inclusive, generous despite suffering\n• Described with his crutch and "his limbs supported by an iron frame"\n• His empty chair and crutch "without an owner" in the future vision\n\nDevelopment Arc: Tim does not develop as a character — he functions as a symbol. His potential death is the emotional catalyst for Scrooge\'s transformation.\n\nExaminer Tip: Tiny Tim is Dickens\'s most powerful weapon against Malthusian ideology. When Scrooge says the poor should "decrease the surplus population," Dickens puts a face to that statistic. Tim\'s disability was likely caused by malnutrition (linked to poverty), making his suffering a direct consequence of social neglect. His survival in Stave 5 proves that generosity literally saves lives.' },
      { id: 'acc-c4', front: 'Jacob Marley\'s Ghost', back: 'Role: Scrooge\'s deceased business partner — appears as a ghost bound in chains to warn Scrooge to change.\n\nKey Quotes:\n• "I wear the chain I forged in life" — every selfish act added a link\n• "Mankind was my business" — realises too late what truly mattered\n• Described with "cash-boxes, keys, padlocks, ledgers, deeds"\n\nDevelopment Arc: Marley is static but prophetic. He exists to show Scrooge what awaits him if he does not repent — an eternity of regret and restless wandering.\n\nExaminer Tip: Marley is Scrooge\'s doppelganger — they were identical in life ("We were alike"), so Marley\'s fate is Scrooge\'s guaranteed future. His chains are a concrete, visual metaphor for how greed imprisons the soul. Link Marley to the Gothic tradition (ghosts, supernatural warnings) and to Dickens\'s use of fear as a tool for moral instruction.' },
      { id: 'acc-c5', front: 'Ghost of Christmas Past', back: 'Role: The first of three spirits — shows Scrooge key memories from his past to reawaken his buried emotions.\n\nKey Quotes/Description:\n• "A strange figure — like a child: yet not so like a child as like an old man" — ambiguous, dreamlike\n• Wears white, emits light from its head, carries a cap that can extinguish its light\n• Scrooge tries to push the cap down to block the light\n\nDevelopment Arc: The Ghost is a supernatural guide, not a character with an arc. It forces Scrooge to feel rather than think.\n\nExaminer Tip: The light symbolises truth and memory — Scrooge trying to extinguish it shows his desire to suppress painful memories. The Ghost\'s childlike/old appearance suggests memory is timeless. This stave establishes empathy: once we understand WHY Scrooge became cold (neglect, loss of Belle), we begin to pity rather than hate him.' },
      { id: 'acc-c6', front: 'Ghost of Christmas Present', back: 'Role: The second spirit — a giant, jolly figure who shows Scrooge how others celebrate Christmas now, and the suffering he ignores.\n\nKey Quotes/Description:\n• Sits on a throne of food — "turkeys, geese, great joints of meat, sucking-pigs"\n• Wears a green robe bordered with white fur, carries a glowing torch\n• Reveals Ignorance and Want beneath his robes\n• Ages visibly during the stave — his life spans only one Christmas Day\n\nDevelopment Arc: The Ghost moves from warmth and abundance to a dark warning (Ignorance and Want), mirroring the novella\'s shift from celebration to social critique.\n\nExaminer Tip: The Ghost embodies Christmas generosity — his torch sprinkles goodwill on the poor. His ageing represents the fleeting nature of the present moment, urging Scrooge (and the reader) to act NOW. The reveal of Ignorance and Want is Dickens\'s most direct political message — address these social evils or face destruction.' },
      { id: 'acc-c7', front: 'Ghost of Christmas Yet to Come', back: 'Role: The third and final spirit — a dark, hooded, silent figure who shows Scrooge a terrifying vision of the future if he does not change.\n\nKey Quotes/Description:\n• "Shrouded in a deep black garment" — associated with death\n• "The Phantom slowly, gravely, silently, approached" — adverb list creates dread\n• Points but never speaks\n\nDevelopment Arc: The Ghost is static and terrifying — it is the culmination of fear that breaks Scrooge\'s resistance and drives him to repent.\n\nExaminer Tip: This Ghost resembles the Grim Reaper — its silence is more powerful than words because Scrooge must interpret the visions himself. The lack of dialogue forces Scrooge into active moral reasoning rather than passive listening. Link to the Gothic genre: darkness, death, fear of the unknown. This stave uses terror where the others used nostalgia and warmth — Dickens understands that different people are moved by different emotions.' },
      { id: 'acc-c8', front: 'Fred (Scrooge\'s nephew)', back: 'Role: Scrooge\'s cheerful, warm-hearted nephew — the son of Scrooge\'s beloved sister Fan. Repeatedly invites Scrooge to Christmas dinner despite constant rejection.\n\nKey Quotes:\n• "I have always thought of Christmas time... as a good time; a kind, forgiving, charitable, pleasant time" — asyndetic list of positive adjectives\n• "I mean to give him the same chance every year, whether he likes it or not" — persistent compassion\n\nDevelopment Arc: Fred does not change — like Bob, he is a moral constant. His unwavering kindness represents the Christmas spirit Scrooge rejects then embraces.\n\nExaminer Tip: Fred is Scrooge\'s foil — same family, same class, opposite values. He proves that wealth does not have to produce miserliness. His connection to Fan (Scrooge\'s sister) is significant: he represents the loving family life Scrooge could have had. Fred\'s persistence shows that compassion should never give up on people — a key Dickensian message.' },
      { id: 'acc-c9', front: 'Belle', back: 'Role: Scrooge\'s former fiancee who breaks off their engagement because his love of money has replaced his love for her.\n\nKey Quotes:\n• "Another idol has displaced me... a golden one" — money as false god\n• "You fear the world too much" — suggests Scrooge\'s greed stems from insecurity\n• She is later seen with a happy family — the life Scrooge lost\n\nDevelopment Arc: Belle appears only in Stave Two as a memory. She represents Scrooge\'s last chance at love and warmth before he fully committed to isolation.\n\nExaminer Tip: Belle\'s departure is the novella\'s key turning point in Scrooge\'s backstory. Her accusation that a "golden idol" has replaced her connects greed to idolatry (a biblical sin), reinforcing Dickens\'s moral framework. The vision of her happy family is designed to make Scrooge feel regret — Dickens shows the reader that the cost of greed is not just money but love, family, and human connection.' },
      { id: 'acc-c10', front: 'Fezziwig', back: 'Role: Scrooge\'s former employer during his apprenticeship — a generous, jovial businessman who treats his workers with warmth and stages a joyful Christmas party.\n\nKey Quotes:\n• "Old Fezziwig laid down his pen... No more work tonight. Christmas Eve, Dick. Christmas!"\n• The narrator notes: "The happiness he gives, is quite as great as if it cost a fortune"\n• Scrooge watches and says quietly: "I should like to be able to say a word or two to my clerk just now"\n\nDevelopment Arc: Fezziwig appears only in Stave Two as a memory. He does not change but serves as a model of how employers should treat workers.\n\nExaminer Tip: Fezziwig is the anti-Scrooge — proof that capitalism and compassion can coexist. Dickens uses him to show that an employer\'s power extends beyond wages: small acts of generosity create immense happiness. The moment Scrooge recognises his failure to be like Fezziwig to Bob Cratchit is a crucial step in his transformation. Link Fezziwig to Dickens\'s argument that the wealthy have a moral duty to their workers.' },

      // ===== THEME CARDS (8) =====
      { id: 'acc-t1', front: 'Theme: Redemption', back: 'Definition: The idea that people can be saved from sin or moral failure by recognising their wrongs and choosing to change.\n\nKey Moments:\n• Marley warns Scrooge he can still escape Marley\'s fate\n• Scrooge weeps at his childhood self (Stave 2) — empathy reawakens\n• Scrooge begs the Ghost of Christmas Yet to Come: "I will honour Christmas in my heart, and try to keep it all the year"\n• Stave 5: Scrooge wakes transformed and immediately acts on his new values\n\nKey Quotes:\n• "I will honour Christmas in my heart" — pledges lasting change\n• "I am as light as a feather, I am as happy as an angel" — joy of transformation\n• "He became as good a friend, as good a master, and as good a man" — transformation across all roles\n\nHow Dickens Presents It: Dickens structures the entire novella around redemption — the five staves mirror the five acts of a morality play. Scrooge\'s journey from sin to salvation follows a Christian template: confession (recognising his wrongs), penance (witnessing consequences), and absolution (being given a second chance). Dickens\'s message is optimistic — no one is beyond saving if they choose to change.' },
      { id: 'acc-t2', front: 'Theme: Social Responsibility', back: 'Definition: The duty of the wealthy and powerful to care for the poor and vulnerable in society.\n\nKey Moments:\n• Scrooge refuses the charity collectors and suggests the poor go to workhouses (Stave 1)\n• Marley\'s ghost declares "Mankind was my business" (Stave 1)\n• The Ghost of Christmas Present reveals Ignorance and Want (Stave 3)\n• Scrooge raises Bob\'s salary and helps his family (Stave 5)\n\nKey Quotes:\n• "Are there no prisons? Are there no workhouses?" — callous dismissal\n• "Mankind was my business" — moral duty recognised too late\n• "This boy is Ignorance. This girl is Want." — allegorical warning\n\nHow Dickens Presents It: Dickens wrote A Christmas Carol partly as a response to a parliamentary report on child labour. He uses the novella as a direct appeal to the wealthy middle classes, arguing that ignoring poverty is both morally wrong and socially dangerous (Ignorance and Want will destroy society). Scrooge\'s transformation models the change Dickens wants from his readers — personal generosity as a first step toward social justice.' },
      { id: 'acc-t3', front: 'Theme: Isolation vs Community', back: 'Definition: The contrast between Scrooge\'s lonely, self-imposed isolation and the warmth of communal celebration and family.\n\nKey Moments:\n• Scrooge spends Christmas Eve alone in his dark chambers (Stave 1)\n• The Cratchit family\'s joyful, crowded Christmas dinner (Stave 3)\n• Fred\'s party — full of laughter, games, and togetherness (Stave 3)\n• In the future, Scrooge dies alone and unmourned — his possessions are stolen (Stave 4)\n• Redeemed Scrooge joins Fred\'s party and becomes a "second father" to Tiny Tim (Stave 5)\n\nKey Quotes:\n• "Solitary as an oyster" — isolation as Scrooge\'s defining trait\n• "A solitary child, neglected by his friends" — roots of isolation in childhood\n• Fred: "I have always thought of Christmas time... as a good time"\n\nHow Dickens Presents It: Dickens juxtaposes Scrooge\'s dark, cold isolation against the bright warmth of every communal scene. Even the poorest characters (the Cratchits, the miners, the lighthouse keepers) find joy in togetherness. Dickens argues that isolation is both the cause and consequence of greed — and that community and connection are the true sources of happiness, regardless of wealth.' },
      { id: 'acc-t4', front: 'Theme: Poverty and Inequality', back: 'Definition: The vast gap between rich and poor in Victorian England, and the suffering caused by the wealthy\'s indifference.\n\nKey Moments:\n• Bob Cratchit earns 15 shillings a week and cannot afford proper coal or medical care for Tim\n• Scrooge dismisses the poor as "surplus population" (Stave 1)\n• The Cratchit Christmas dinner — they make the most of very little (Stave 3)\n• Ignorance and Want — starving, ragged children hidden beneath the Ghost\'s robes (Stave 3)\n• In Stave 4, the poor steal from Scrooge\'s corpse — poverty breeds desperation\n\nKey Quotes:\n• "If he be like to die, he had better do it, and decrease the surplus population" — Malthusian cruelty\n• "This boy is Ignorance. This girl is Want." — social consequences of neglect\n\nHow Dickens Presents It: Dickens does not sentimentalise poverty — he shows it kills (Tiny Tim), degrades (Ignorance and Want), and corrupts (the thieves in Stave 4). He places blame squarely on the wealthy, not the poor. The Cratchits\' dignity despite poverty contrasts with Scrooge\'s moral poverty despite wealth, inverting the Victorian assumption that the rich are morally superior.' },
      { id: 'acc-t5', front: 'Theme: Christmas and Generosity', back: 'Definition: Christmas as a time of kindness, charity, forgiveness, and communal joy — a moral ideal that should extend beyond one day.\n\nKey Moments:\n• Fred defends Christmas as "a kind, forgiving, charitable, pleasant time" (Stave 1)\n• Fezziwig\'s Christmas party — generosity costs little but means everything (Stave 2)\n• The Ghost of Christmas Present\'s torch spreads warmth to the poor (Stave 3)\n• Scrooge buys the prize turkey for the Cratchits and donates to charity (Stave 5)\n• "He knew how to keep Christmas well, if any man alive possessed the knowledge" (Stave 5)\n\nKey Quotes:\n• "God bless us, every one!" — Tim\'s universal goodwill\n• "I will honour Christmas in my heart, and try to keep it all the year"\n\nHow Dickens Presents It: Dickens uses Christmas as a vehicle for his social message — it is not about religion alone but about the principle of generosity toward all people. The key phrase is "keep it all the year" — Dickens argues Christmas spirit must be a permanent way of living, not a single day of charity. The novella itself was published at Christmas 1843 and was intended as a "Christmas gift" to readers that would inspire real social change.' },
      { id: 'acc-t6', front: 'Theme: Family', back: 'Definition: The importance of family bonds, and how both the presence and absence of family shape characters\' lives.\n\nKey Moments:\n• Young Scrooge is left alone at school — abandoned by his father (Stave 2)\n• Fan collects Scrooge: "Father is so much kinder than he used to be" (Stave 2)\n• Belle\'s happy family — the life Scrooge rejected (Stave 2)\n• The Cratchits\' loving Christmas dinner (Stave 3)\n• Fred keeps inviting Scrooge — family loyalty despite rejection (Staves 1 & 3)\n• Scrooge becomes "a second father to Tiny Tim" (Stave 5)\n\nKey Quotes:\n• "A solitary child, neglected by his friends" — childhood loneliness\n• "God bless us, every one!" — family as source of moral goodness\n\nHow Dickens Presents It: Dickens shows that family is not about wealth but about love and togetherness. The Cratchits have almost nothing but are emotionally rich; Scrooge has everything but is emotionally bankrupt. Scrooge\'s backstory reveals that his isolation began with family breakdown (absent father). His redemption ends with family restoration — he re-enters Fred\'s family and adopts the Cratchits. Dickens argues that family and community are the foundations of a moral society.' },
      { id: 'acc-t7', front: 'Theme: Time and Regret', back: 'Definition: The idea that time is limited, the past cannot be changed, but the future is still within our control if we act now.\n\nKey Moments:\n• Marley\'s ghost regrets wasting his time alive on greed (Stave 1)\n• Ghost of Christmas Past shows Scrooge moments he can never undo (Stave 2)\n• Ghost of Christmas Present ages and dies within a single stave — time is short (Stave 3)\n• Ghost of Christmas Yet to Come shows a future that has not happened yet (Stave 4)\n• Scrooge wakes and exclaims: "I will live in the Past, the Present, and the Future!" (Stave 5)\n\nKey Quotes:\n• "I wear the chain I forged in life" — the past creates consequences\n• "The Spirits of all Three shall strive within me" — learning from every time period\n\nHow Dickens Presents It: The three-ghost structure literally moves through past, present, and future — Dickens shows that understanding all three is necessary for moral growth. The past explains why we are who we are; the present shows the consequences of our choices on others; the future warns us what will happen if we do not change. Dickens\'s message: it is never too late to change, but you must act now because time is running out.' },
      { id: 'acc-t8', front: 'Theme: The Supernatural', back: 'Definition: The use of ghosts, spirits, and otherworldly elements to convey moral and social messages.\n\nKey Moments:\n• Marley\'s face appears on Scrooge\'s door knocker (Stave 1)\n• Marley\'s ghost appears in chains, jaw bandage, transparent body (Stave 1)\n• Three spirits visit Scrooge on successive nights — each more frightening\n• The Ghost of Christmas Yet to Come is the most terrifying: silent, shrouded, deathlike (Stave 4)\n\nKey Quotes:\n• "Old Marley was as dead as a door-nail" — establishes the supernatural premise\n• "The Phantom slowly, gravely, silently, approached" — dread and fear\n\nHow Dickens Presents It: Dickens draws on the Gothic tradition and the Victorian fascination with ghosts. The supernatural serves a moral purpose — the ghosts are not there to terrify for entertainment but to force Scrooge (and the reader) into self-reflection. Each ghost escalates in fear: nostalgia, warmth, then sheer terror. Dickens uses the ghost story format to make his social critique palatable and entertaining — readers came for the ghosts and left thinking about poverty and compassion.' },

      // ===== CONTEXT CARDS (7) =====
      { id: 'acc-cx1', front: 'Context: Victorian Workhouses', back: 'Key Facts:\n• The 1834 Poor Law Amendment Act established workhouses as the main form of relief for the poor.\n• Conditions were deliberately harsh to deter people from seeking help — families were separated, food was minimal, work was gruelling.\n• They were seen as shameful; entering one meant you had "failed."\n• Many Victorians believed poverty was caused by laziness, not systemic injustice.\n\nConnection to the Novella:\n• Scrooge refers to workhouses when asked to donate: "Are there no prisons? Are there no workhouses?"\n• He uses their existence to justify his refusal to help — the state has "provided" for the poor.\n• Dickens directly attacks this attitude: the charity collectors reply that many "would rather die" than enter workhouses.\n\nUseful for AO3: Shows Dickens writing to challenge the dominant ideology of his time. His contemporary readers would have recognised Scrooge\'s attitude as common among the wealthy. Dickens argues that workhouses are not charity — they are punishment disguised as help. Link to Dickens\'s own childhood experience of poverty when his father was imprisoned for debt.' },
      { id: 'acc-cx2', front: 'Context: Malthusian Economics', back: 'Key Facts:\n• Thomas Malthus (1766-1834) argued that population growth would always outstrip food supply, leading to poverty and famine.\n• His theory was used to justify not helping the poor — if they were "surplus," helping them would only make the problem worse.\n• Many wealthy Victorians adopted Malthusian views to ease their conscience about poverty.\n• The phrase "surplus population" was well known in Dickens\'s time.\n\nConnection to the Novella:\n• Scrooge directly echoes Malthus: "If he be like to die, he had better do it, and decrease the surplus population."\n• The Ghost of Christmas Present throws these words back at Scrooge when he asks about Tiny Tim\'s fate.\n• Dickens personifies the "surplus population" as a real, innocent child to dismantle the cold abstraction of Malthusian theory.\n\nUseful for AO3: Demonstrates that Dickens was engaging with specific contemporary economic debates, not just telling a ghost story. His novella is a direct counter-argument to Malthus: the poor are not statistics but people. This context elevates your analysis from character study to political commentary.' },
      { id: 'acc-cx3', front: 'Context: Dickens\'s Own Life', back: 'Key Facts:\n• Charles Dickens (1812-1870) experienced poverty firsthand — aged 12, he worked in a blacking factory while his father was in debtors\' prison.\n• This traumatic experience shaped his lifelong sympathy for the poor and hatred of institutions that failed them.\n• Dickens wrote A Christmas Carol in just six weeks in 1843, partly in response to a parliamentary report on child labour.\n• He personally funded the publication to keep the price low (5 shillings) so more people could read it.\n\nConnection to the Novella:\n• Young Scrooge\'s loneliness at boarding school may reflect Dickens\'s own childhood feelings of abandonment.\n• Dickens\'s belief that no child should suffer poverty drives the characterisation of Tiny Tim and the children Ignorance and Want.\n• The novella was intended as a practical act of social reform — Dickens called it "a sledgehammer" blow for the poor.\n\nUseful for AO3: Linking the text to Dickens\'s biography shows sophisticated understanding of authorial intent. Dickens did not write from a position of privilege — he understood poverty from the inside. This gives his critique of the wealthy extra moral authority and emotional power.' },
      { id: 'acc-cx4', front: 'Context: Christianity and Victorian Morality', back: 'Key Facts:\n• Victorian Britain was an overwhelmingly Christian society — church attendance was expected, and Christian values (charity, forgiveness, love) were publicly endorsed.\n• However, many wealthy Christians ignored the biblical instruction to help the poor, using Malthusian economics as justification.\n• The hypocrisy of professing Christianity while ignoring suffering was a major target for social reformers like Dickens.\n\nConnection to the Novella:\n• Tiny Tim\'s "God bless us, every one!" is a direct Christian message of universal goodwill.\n• Scrooge\'s transformation follows a Christian pattern: sin, repentance, redemption, and salvation.\n• Marley\'s chains and eternal punishment echo the Christian concept of damnation for the greedy.\n• Fred defends Christmas as "a kind, forgiving, charitable, pleasant time" — listing Christian virtues.\n\nUseful for AO3: Dickens weaponises Christianity against the hypocritical wealthy. He essentially asks: how can you call yourself a Christian while letting children starve? The novella\'s moral framework is explicitly Christian — sin, repentance, and redemption — making it both a ghost story and a sermon. This dual purpose is key to understanding Dickens\'s craft.' },
      { id: 'acc-cx5', front: 'Context: The Industrial Revolution', back: 'Key Facts:\n• By the 1840s, Britain was the world\'s leading industrial power — factories, railways, and mass production had transformed the economy.\n• Industrialisation created enormous wealth for factory owners and businessmen but appalling conditions for workers: long hours, low pay, dangerous work, child labour.\n• Cities like London and Manchester grew rapidly, creating overcrowded slums with poor sanitation, disease, and high mortality.\n• The gap between rich and poor widened dramatically.\n\nConnection to the Novella:\n• Scrooge represents the new industrial capitalist — wealthy, self-made, but morally bankrupt.\n• Marley\'s chain includes "cash-boxes, keys, padlocks, ledgers" — the tools of commerce.\n• Bob Cratchit is the exploited worker: underpaid, overworked, unable to afford heating or medical care.\n• Fezziwig represents the older, more humane model of business — personal, generous, community-minded.\n\nUseful for AO3: Dickens contrasts Fezziwig\'s paternalistic capitalism (where employers feel responsible for workers) with Scrooge\'s new, impersonal capitalism (where workers are expendable). This context helps explain why Dickens frames the solution as personal generosity rather than political revolution — he wanted to reform the hearts of the wealthy, not overthrow the system.' },
      { id: 'acc-cx6', front: 'Context: The Ghost Story Tradition', back: 'Key Facts:\n• Ghost stories were a popular Victorian Christmas tradition — families would gather around the fire on Christmas Eve to share supernatural tales.\n• The Gothic genre (Frankenstein, 1818; early Poe stories) had made supernatural fiction respectable and popular.\n• Dickens was a master of the ghost story format and published many in his magazines.\n• A Christmas Carol was published on 19 December 1843 — timed for the Christmas market.\n\nConnection to the Novella:\n• Dickens uses the ghost story format to deliver a serious social message in an entertaining package.\n• The three spirits escalate in fear: nostalgic (Past), warm then warning (Present), terrifying (Yet to Come).\n• Marley\'s ghost draws on Gothic conventions: chains, wailing, transparent body, jaw bandage.\n• The novella\'s structure (a haunting that leads to transformation) gives the moral message dramatic power.\n\nUseful for AO3: Understanding genre helps you analyse HOW Dickens delivers his message, not just WHAT it is. He chose the ghost story deliberately — it was the most popular and accessible form of Christmas entertainment. By embedding social criticism inside a ghost story, Dickens ensured maximum readership and emotional impact. This is a strong point for discussing Dickens\'s methods and craft (AO2).' },
      { id: 'acc-cx7', front: 'Context: The Structure of Five Staves', back: 'Key Facts:\n• Dickens divides the novella into five "staves" rather than chapters — a "stave" is a verse of a song or a staff of music.\n• This musical terminology reinforces the title: the novella is a "carol," a song of joy.\n• The five-stave structure mirrors a five-act play or morality tale: exposition, complication, climax, crisis, resolution.\n• The novella was designed to be read aloud — Dickens himself performed public readings of it throughout his life.\n\nConnection to the Novella:\n• Stave 1: Establishes Scrooge\'s miserliness and introduces the supernatural premise.\n• Stave 2: Explores Scrooge\'s past — builds empathy.\n• Stave 3: Shows the present — contrasts poverty with generosity, introduces Ignorance and Want.\n• Stave 4: The dark future — fear drives Scrooge to repent.\n• Stave 5: Redemption and joy — the "carol" reaches its uplifting conclusion.\n\nUseful for AO3: The term "stave" signals that this is not just a story but a performance — a song intended to move and inspire. The cyclical structure (beginning and ending on Christmas morning) suggests renewal and rebirth. Discussing Dickens\'s structural choices shows sophisticated understanding of form and is an excellent way to address AO2 (methods) in your exam response.' },
    ],
  },
  ...poetryFlashcardDecks,
  ...setTextFlashcardDecks,
  ...vocabularyDecks,
  ...examTechniqueDecks,
];

